export enum Severity {
  HIGH = 'HIGH',
  MEDIUM = 'MEDIUM',
  LOW = 'LOW'
}

export enum IncidentType {
  DEVICE = 'DEVICE',   // Sự cố thiết bị
  GAME = 'GAME',       // Sự cố máy game
  ACCIDENT = 'ACCIDENT' // Sự cố tai nạn
}

export enum DeviceStatus {
  UNSAFE = 'UNSAFE',         // Không an toàn
  BROKEN = 'BROKEN',         // Hỏng hẳn
  WAITING_PARTS = 'WAITING_PARTS', // Chờ đồ thay
  FIXED = 'FIXED'            // Đã sửa
}

export interface Incident {
  id: string;
  branchId: string;
  title: string;
  description: string;
  severity: Severity;
  type: IncidentType;
  timestamp: number;
  imageUrls: string[]; 
  reporterName: string;
  reporterRole: string; 
  isResolved: boolean;
  deviceStatus?: DeviceStatus;
  setupResponse?: string;
  resolutionNote?: string;
  resolutionImageUrls?: string[];
}

export interface Branch {
  id: string;
  name: string;
  created_at?: string;
}

// Danh sách mặc định để khởi tạo nếu DB trống
export const DEFAULT_BRANCHES: Partial<Branch>[] = [
  { name: 'CN Go Thái Bình' },
  { name: 'CN Vincom Bắc Từ Liêm' },
  { name: 'CN Vincom Trần Duy Hưng' },
  { name: 'CN Time City' },
  { name: 'CN Royal City' },
];

import React, { useState } from 'react';
import { Branch, Incident, Severity, IncidentType } from '../types';

interface AdminPanelProps {
  branches: Branch[];
  incidents: Incident[];
  onAddBranch: (name: string) => Promise<void>;
  onUpdateBranch: (id: string, name: string) => Promise<void>;
  onDeleteBranch: (id: string) => Promise<void>;
  onDeleteIncident: (id: string) => Promise<void>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  branches, 
  incidents, 
  onAddBranch, 
  onUpdateBranch, 
  onDeleteBranch,
  onDeleteIncident 
}) => {
  const [adminTab, setAdminTab] = useState<'stats' | 'branches' | 'incidents'>('stats');
  const [newBranchName, setNewBranchName] = useState('');
  const [editingBranch, setEditingBranch] = useState<{id: string, name: string} | null>(null);

  // Stats Logic
  const totalIncidents = incidents.length;
  const highSeverityCount = incidents.filter(i => i.severity === Severity.HIGH).length;
  const resolvedCount = incidents.filter(i => i.isResolved).length;
  const resolvedRate = totalIncidents > 0 ? Math.round((resolvedCount / totalIncidents) * 100) : 0;

  const handleAdd = async () => {
    if (!newBranchName.trim()) return;
    await onAddBranch(newBranchName.trim());
    setNewBranchName('');
  };

  const handleUpdate = async () => {
    if (!editingBranch || !editingBranch.name.trim()) return;
    await onUpdateBranch(editingBranch.id, editingBranch.name.trim());
    setEditingBranch(null);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Admin Sub-navigation */}
      <div className="flex border-b border-gray-200 bg-white rounded-t-xl overflow-hidden">
        <button 
          onClick={() => setAdminTab('stats')}
          className={`flex-1 py-3 text-sm font-bold transition-colors ${adminTab === 'stats' ? 'bg-indigo-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <i className="fas fa-chart-line mr-2"></i>Tổng quan
        </button>
        <button 
          onClick={() => setAdminTab('branches')}
          className={`flex-1 py-3 text-sm font-bold transition-colors ${adminTab === 'branches' ? 'bg-indigo-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <i className="fas fa-store mr-2"></i>Chi nhánh
        </button>
        <button 
          onClick={() => setAdminTab('incidents')}
          className={`flex-1 py-3 text-sm font-bold transition-colors ${adminTab === 'incidents' ? 'bg-indigo-600 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <i className="fas fa-exclamation-triangle mr-2"></i>Sự cố
        </button>
      </div>

      <div className="bg-white p-4 md:p-6 rounded-b-xl shadow-sm border border-t-0 border-gray-200 min-h-[400px]">
        {/* STATS VIEW */}
        {adminTab === 'stats' && (
          <div className="space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100">
                <div className="text-2xl font-black text-indigo-700">{totalIncidents}</div>
                <div className="text-xs font-bold text-indigo-500 uppercase">Tổng sự cố</div>
              </div>
              <div className="p-4 bg-rose-50 rounded-xl border border-rose-100">
                <div className="text-2xl font-black text-rose-700">{highSeverityCount}</div>
                <div className="text-xs font-bold text-rose-500 uppercase">Khẩn cấp</div>
              </div>
              <div className="p-4 bg-green-50 rounded-xl border border-green-100">
                <div className="text-2xl font-black text-green-700">{resolvedCount}</div>
                <div className="text-xs font-bold text-green-500 uppercase">Đã xử lý</div>
              </div>
              <div className="p-4 bg-amber-50 rounded-xl border border-amber-100">
                <div className="text-2xl font-black text-amber-700">{resolvedRate}%</div>
                <div className="text-xs font-bold text-amber-500 uppercase">Tỉ lệ xử lý</div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="border rounded-xl p-4">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center">
                  <i className="fas fa-list-ol mr-2 text-indigo-500"></i>Phân loại sự cố
                </h4>
                <div className="space-y-3">
                  {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(type => {
                    const count = incidents.filter(i => i.type === type).length;
                    const pct = totalIncidents > 0 ? (count / totalIncidents) * 100 : 0;
                    const labels = { [IncidentType.DEVICE]: 'Thiết bị', [IncidentType.GAME]: 'Máy game', [IncidentType.ACCIDENT]: 'Tai nạn' };
                    return (
                      <div key={type}>
                        <div className="flex justify-between text-xs font-bold mb-1">
                          <span>{labels[type]}</span>
                          <span>{count} ({Math.round(pct)}%)</span>
                        </div>
                        <div className="w-full bg-gray-100 rounded-full h-2">
                          <div className={`h-2 rounded-full ${type === IncidentType.ACCIDENT ? 'bg-rose-500' : type === IncidentType.GAME ? 'bg-purple-500' : 'bg-indigo-500'}`} style={{width: `${pct}%`}}></div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              <div className="border rounded-xl p-4">
                <h4 className="font-bold text-gray-700 mb-4 flex items-center">
                  <i className="fas fa-trophy mr-2 text-yellow-500"></i>Top Chi nhánh (Sự cố)
                </h4>
                <div className="space-y-2">
                  {branches.map(b => ({...b, count: incidents.filter(i => i.branchId === b.id).length}))
                    .sort((a, b) => b.count - a.count)
                    .slice(0, 5)
                    .map((b, idx) => (
                      <div key={b.id} className="flex justify-between items-center text-sm p-2 bg-gray-50 rounded">
                        <span className="font-medium text-gray-600">{idx+1}. {b.name}</span>
                        <span className="font-bold text-indigo-600 bg-white px-2 py-0.5 rounded shadow-sm">{b.count}</span>
                      </div>
                    ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* BRANCH MANAGEMENT */}
        {adminTab === 'branches' && (
          <div className="space-y-6">
            <div className="flex gap-2">
              <input 
                type="text" 
                placeholder="Tên chi nhánh mới..." 
                className="flex-1 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-200 outline-none"
                value={newBranchName}
                onChange={(e) => setNewBranchName(e.target.value)}
              />
              <button 
                onClick={handleAdd}
                className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-indigo-700 transition-colors"
              >
                <i className="fas fa-plus mr-2"></i>Thêm
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead>
                  <tr className="bg-gray-100 text-gray-600 font-bold">
                    <th className="p-3 rounded-l-lg">Tên Chi Nhánh</th>
                    <th className="p-3 text-center">Sự cố</th>
                    <th className="p-3 text-right rounded-r-lg">Thao tác</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {branches.map(branch => (
                    <tr key={branch.id} className="hover:bg-gray-50 transition-colors">
                      <td className="p-3 font-medium">
                        {editingBranch?.id === branch.id ? (
                          <input 
                            className="border rounded px-2 py-1 w-full"
                            value={editingBranch.name}
                            onChange={(e) => setEditingBranch({...editingBranch, name: e.target.value})}
                            autoFocus
                          />
                        ) : branch.name}
                      </td>
                      <td className="p-3 text-center font-bold text-gray-400">
                        {incidents.filter(i => i.branchId === branch.id).length}
                      </td>
                      <td className="p-3 text-right space-x-2">
                        {editingBranch?.id === branch.id ? (
                          <>
                            <button onClick={handleUpdate} className="text-green-600 hover:text-green-800 p-1"><i className="fas fa-check"></i></button>
                            <button onClick={() => setEditingBranch(null)} className="text-gray-400 hover:text-gray-600 p-1"><i className="fas fa-times"></i></button>
                          </>
                        ) : (
                          <>
                            <button onClick={() => setEditingBranch({id: branch.id, name: branch.name})} className="text-indigo-600 hover:text-indigo-800 p-1" title="Sửa"><i className="fas fa-edit"></i></button>
                            <button onClick={() => { if(window.confirm('Xóa chi nhánh này?')) onDeleteBranch(branch.id) }} className="text-rose-600 hover:text-rose-800 p-1" title="Xóa"><i className="fas fa-trash"></i></button>
                          </>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* INCIDENT MANAGEMENT */}
        {adminTab === 'incidents' && (
          <div className="space-y-4">
            <p className="text-xs text-gray-500 italic">Admin có quyền xóa các báo cáo sai hoặc không hợp lệ.</p>
            <div className="overflow-x-auto">
              <table className="w-full text-left text-xs md:text-sm">
                <thead>
                  <tr className="bg-gray-100 text-gray-600 font-bold">
                    <th className="p-3 rounded-l-lg">Ngày/Giờ</th>
                    <th className="p-3">Tiêu đề</th>
                    <th className="p-3">Chi nhánh</th>
                    <th className="p-3">Mức độ</th>
                    <th className="p-3 text-right rounded-r-lg">Thao tác</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {incidents.map(incident => (
                    <tr key={incident.id} className="hover:bg-gray-50">
                      <td className="p-3 text-gray-500 whitespace-nowrap">
                        {new Date(incident.timestamp).toLocaleString('vi-VN', {day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit'})}
                      </td>
                      <td className="p-3 font-bold truncate max-w-[150px]">{incident.title}</td>
                      <td className="p-3">{branches.find(b => b.id === incident.branchId)?.name || 'N/A'}</td>
                      <td className="p-3">
                        <span className={`px-2 py-0.5 rounded-full font-bold text-[10px] uppercase ${incident.severity === Severity.HIGH ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-600'}`}>
                          {incident.severity}
                        </span>
                      </td>
                      <td className="p-3 text-right">
                        <button 
                          onClick={() => { if(window.confirm('Xóa báo cáo sự cố này?')) onDeleteIncident(incident.id) }} 
                          className="bg-rose-100 text-rose-600 w-8 h-8 rounded-lg hover:bg-rose-200 transition-colors"
                        >
                          <i className="fas fa-trash-alt"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                  {incidents.length === 0 && (
                    <tr><td colSpan={5} className="p-10 text-center text-gray-400">Không có dữ liệu sự cố.</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useRef } from 'react';
import { Branch, Incident, Severity, IncidentType, DeviceStatus, DEFAULT_BRANCHES } from './types';
import IncidentCard from './components/IncidentCard';
import WatermarkCamera from './components/WatermarkCamera';
import AdminPanel from './components/AdminPanel';
import { playAlertSound } from './utils';
import { getSupabase, initSupabase, resetSupabaseConfig } from './utils/supabaseClient';
import { RealtimeChannel } from '@supabase/supabase-js';

// --- SUB-COMPONENT: Branch Section ---
interface BranchSectionProps {
  branch: Branch;
  incidents: Incident[];
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
}

const BranchSection: React.FC<BranchSectionProps> = ({ branch, incidents, onUpdate }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const sortedIncidents = [...incidents].sort((a, b) => {
    const severityScore = { [Severity.HIGH]: 3, [Severity.MEDIUM]: 2, [Severity.LOW]: 1 };
    const scoreA = severityScore[a.severity] || 0;
    const scoreB = severityScore[b.severity] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    return b.timestamp - a.timestamp;
  });

  const visibleIncidents = isExpanded ? sortedIncidents : sortedIncidents.slice(0, 3);
  const hiddenCount = sortedIncidents.length - 3;
  const hasMore = sortedIncidents.length > 3;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-6 transition-all duration-300">
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-fkPurple rounded-full"></div>
          <h2 className="text-base md:text-lg font-bold text-gray-800">{branch.name}</h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{incidents.length}</span>
        </div>
        {hasMore && (
           <button onClick={() => setIsExpanded(!isExpanded)} className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center transition-colors px-2 py-1 rounded hover:bg-indigo-50">
             {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sự cố`}
             <i className={`fas fa-chevron-${isExpanded ? 'up' : 'right'} ml-1.5`}></i>
           </button>
        )}
      </div>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-6">
        {visibleIncidents.map(incident => <IncidentCard key={incident.id} incident={incident} onUpdate={onUpdate} />)}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'report' | 'export' | 'admin'>('dashboard');
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<string>('all');
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<'all' | 'unresolved' | 'resolved'>('unresolved');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState<'all' | IncidentType>('all');
  const [lastUpdated, setLastUpdated] = useState<number>(Date.now());
  const [isMuted, setIsMuted] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [connectionError, setConnectionError] = useState('');

  const subscriptionRef = useRef<RealtimeChannel | null>(null);

  useEffect(() => {
    const sb = getSupabase();
    if (sb) {
      setIsConfigured(true);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    }
    return () => { if (subscriptionRef.current) subscriptionRef.current.unsubscribe(); };
  }, []);

  const setupRealtime = (sb: any) => {
    if (subscriptionRef.current) subscriptionRef.current.unsubscribe();
    subscriptionRef.current = sb.channel('all-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'incidents' }, () => { fetchIncidents(); playAlertSound(); })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, () => { fetchBranches(); })
      .subscribe();
  };

  const handleSaveConfig = () => {
    try {
      setConnectionError('');
      const sb = initSupabase(configUrl.trim(), configKey.trim());
      setIsConfigured(true);
      setShowConfigModal(false);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } catch (e) { setConnectionError('Cấu hình không hợp lệ.'); }
  };

  const fetchBranches = async () => {
    const sb = getSupabase();
    if (!sb) return;
    const { data, error } = await sb.from('branches').select('*').order('name');
    if (!error && data) setBranches(data);
  };

  const fetchIncidents = async () => {
    const sb = getSupabase();
    if (!sb) return;
    setIsLoading(true);
    const { data, error } = await sb.from('incidents').select('*').order('timestamp', { ascending: false });
    if (!error) { setIncidents(data || []); setLastUpdated(Date.now()); }
    setIsLoading(false);
  };

  // Admin Actions
  const handleAddBranch = async (name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').insert([{ name }]);
    fetchBranches();
  };

  const handleUpdateBranch = async (id: string, name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').update({ name }).eq('id', id);
    fetchBranches();
  };

  const handleDeleteBranch = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').delete().eq('id', id);
    fetchBranches();
  };

  const handleDeleteIncident = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('incidents').delete().eq('id', id);
    fetchIncidents();
  };

  // Audio Logic
  useEffect(() => {
    const hasActiveHighSeverity = incidents.some(i => i.severity === Severity.HIGH && !i.isResolved);
    let interval: number;
    if (hasActiveHighSeverity && !isMuted) {
      playAlertSound();
      interval = window.setInterval(playAlertSound, 5000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [incidents, isMuted]);

  // Form State
  const [formBranchId, setFormBranchId] = useState('');
  useEffect(() => { if (branches.length > 0 && !formBranchId) setFormBranchId(branches[0].id); }, [branches]);

  const [formType, setFormType] = useState<IncidentType>(IncidentType.DEVICE);
  const [formTitle, setFormTitle] = useState('');
  const [formDesc, setFormDesc] = useState('');
  const [formSeverity, setFormSeverity] = useState<Severity>(Severity.LOW);
  const [formImages, setFormImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formReporterName, setFormReporterName] = useState('');
  const [formReporterRole, setFormReporterRole] = useState('');

  const uploadImage = async (base64Image: string): Promise<string | null> => {
    const sb = getSupabase();
    if (!sb) return null;
    try {
      const base64Str = base64Image.split(',')[1];
      const byteCharacters = atob(base64Str);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'image/jpeg' });
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.jpg`;
      const { data, error } = await sb.storage.from('incident-images').upload(fileName, blob, { contentType: 'image/jpeg' });
      if (error) return null;
      const { data: { publicUrl } } = sb.storage.from('incident-images').getPublicUrl(fileName);
      return publicUrl;
    } catch { return null; }
  };

  const handleUpdateIncident = async (id: string, updates: Partial<Incident>) => {
    const sb = getSupabase();
    if (!sb) return;
    let finalUpdates = { ...updates };
    if (updates.resolutionImageUrls) {
       const uploaded = await Promise.all(updates.resolutionImageUrls.map(async img => img.startsWith('data:') ? await uploadImage(img) : img));
       finalUpdates.resolutionImageUrls = uploaded.filter(u => u !== null) as string[];
    }
    await sb.from('incidents').update(finalUpdates).eq('id', id);
    fetchIncidents();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sb = getSupabase();
    if (!sb) { setShowConfigModal(true); return; }
    if (!formReporterName || !formReporterRole || !formBranchId) { alert('Vui lòng điền đủ thông tin'); return; }
    setIsSubmitting(true);
    const uploadedImageUrls: string[] = [];
    for (const base64 of formImages) { const url = await uploadImage(base64); if (url) uploadedImageUrls.push(url); }
    const { error } = await sb.from('incidents').insert([{
      branchId: formBranchId, title: formTitle, description: formDesc, severity: formSeverity, type: formType,
      timestamp: Date.now(), imageUrls: uploadedImageUrls, reporterName: formReporterName, reporterRole: formReporterRole, isResolved: false
    }]);
    setIsSubmitting(false);
    if (!error) { fetchIncidents(); setFormTitle(''); setFormDesc(''); setFormImages([]); setActiveTab('dashboard'); }
  };

  const filteredIncidents = incidents.filter(i => {
    const bMatch = selectedBranchFilter === 'all' || i.branchId === selectedBranchFilter;
    const sMatch = selectedStatusFilter === 'all' ? true : selectedStatusFilter === 'resolved' ? i.isResolved : !i.isResolved;
    const tMatch = selectedTypeFilter === 'all' || i.type === selectedTypeFilter;
    return bMatch && sMatch && tMatch;
  });

  const inputStyle = "w-full rounded-lg border border-indigo-500 bg-white text-black text-base p-3 focus:border-indigo-700 focus:ring-2 focus:ring-indigo-200 outline-none transition-all placeholder-gray-400 font-medium appearance-none";
  const labelStyle = "block text-sm font-bold text-gray-700 mb-2";

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-gradient-to-r from-fkRed to-fkPurple text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-screen-xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center space-x-3 cursor-pointer" onClick={() => setActiveTab('dashboard')}>
            <div className="bg-white/20 p-2 rounded-full"><i className="fas fa-child text-xl md:text-2xl"></i></div>
            <div><h1 className="text-lg md:text-xl font-bold tracking-tight">FunnyKids</h1><span className="text-xs font-light opacity-80">Incident Manager</span></div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setShowConfigModal(true)} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 border border-white/20 transition-all"><i className="fas fa-cog"></i></button>
            <button onClick={() => setIsMuted(!isMuted)} className={`flex items-center gap-2 px-3 py-2 rounded-lg border ${isMuted ? 'bg-red-500/20 text-red-100 border-red-400/50' : 'bg-white/10 text-white border-white/20'}`}>
              <i className={`fas ${isMuted ? 'fa-volume-mute' : 'fa-volume-up'}`}></i><span className="text-xs font-bold hidden md:inline">{isMuted ? 'Muted' : 'Sound ON'}</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="bg-white shadow-sm border-b sticky top-[60px] z-40">
        <div className="max-w-screen-xl mx-auto flex">
          <button onClick={() => setActiveTab('dashboard')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'dashboard' ? 'border-fkPurple text-fkPurple bg-indigo-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-th-large"></i></div>Theo dõi
          </button>
          <button onClick={() => setActiveTab('report')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'report' ? 'border-fkRed text-fkRed bg-red-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-plus-circle"></i></div>Báo cáo
          </button>
          <button onClick={() => { 
            const pass = window.prompt("Nhập mật khẩu quản trị (Demo: 123)"); 
            if (pass === '123') setActiveTab('admin'); 
            else if (pass !== null) alert("Mật khẩu sai!");
          }} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'admin' ? 'border-indigo-600 text-indigo-600 bg-indigo-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-user-shield"></i></div>Quản trị
          </button>
          <button onClick={() => setActiveTab('export')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'export' ? 'border-green-600 text-green-600 bg-green-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-file-export"></i></div>Xuất file
          </button>
        </div>
      </nav>

      <main className="flex-grow max-w-screen-xl w-full mx-auto px-4 py-6">
        {activeTab === 'dashboard' && (
          <div className="space-y-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-4">
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Trạng thái</label>
               <select value={selectedStatusFilter} onChange={(e) => setSelectedStatusFilter(e.target.value as any)} className={inputStyle}><option value="unresolved">Chưa xử lý</option><option value="resolved">Đã xử lý</option><option value="all">Tất cả</option></select></div>
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Loại sự cố</label>
               <select value={selectedTypeFilter} onChange={(e) => setSelectedTypeFilter(e.target.value as any)} className={inputStyle}><option value="all">Tất cả loại</option><option value={IncidentType.DEVICE}>Thiết bị</option><option value={IncidentType.GAME}>Máy game</option><option value={IncidentType.ACCIDENT}>Tai nạn</option></select></div>
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Chi nhánh</label>
               <select value={selectedBranchFilter} onChange={(e) => setSelectedBranchFilter(e.target.value)} className={inputStyle}><option value="all">Tất cả chi nhánh</option>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
            </div>
            {isLoading ? <div className="text-center py-20 text-gray-300"><i className="fas fa-circle-notch fa-spin text-4xl mb-2"></i><p>Đang tải dữ liệu...</p></div> : 
              branches.filter(b => selectedBranchFilter === 'all' || b.id === selectedBranchFilter).map(branch => {
                const bIncidents = filteredIncidents.filter(i => i.branchId === branch.id);
                return bIncidents.length > 0 ? <BranchSection key={branch.id} branch={branch} incidents={bIncidents} onUpdate={handleUpdateIncident} /> : null;
              })
            }
          </div>
        )}

        {activeTab === 'report' && (
          <div className="max-w-3xl mx-auto bg-white rounded-xl shadow-lg p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-6 border-b pb-4">Báo cáo sự cố mới</h2>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(t => (
                  <div key={t} onClick={() => setFormType(t)} className={`cursor-pointer border-2 p-4 rounded-lg flex flex-col items-center transition-all ${formType === t ? 'border-fkPurple bg-indigo-50 text-indigo-700' : 'border-gray-100'}`}>
                    <i className={`fas ${t === IncidentType.DEVICE ? 'fa-tools' : t === IncidentType.GAME ? 'fa-gamepad' : 'fa-user-injured'} text-2xl mb-2`}></i>
                    <span className="font-bold text-sm">{t === IncidentType.DEVICE ? 'Thiết bị' : t === IncidentType.GAME ? 'Máy game' : 'Tai nạn'}</span>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className={labelStyle}>Người báo <span className="text-red-500">*</span></label><input type="text" required value={formReporterName} onChange={(e) => setFormReporterName(e.target.value)} className={inputStyle} /></div>
                <div><label className={labelStyle}>Chức vụ <span className="text-red-500">*</span></label><input type="text" required value={formReporterRole} onChange={(e) => setFormReporterRole(e.target.value)} className={inputStyle} /></div>
              </div>
              <div><label className={labelStyle}>Chi nhánh <span className="text-red-500">*</span></label><select value={formBranchId} onChange={(e) => setFormBranchId(e.target.value)} className={inputStyle}>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
              <div><label className={labelStyle}>Hình ảnh</label><WatermarkCamera images={formImages} onImagesChange={setFormImages} /></div>
              <div><label className={labelStyle}>Tiêu đề <span className="text-red-500">*</span></label><input type="text" required value={formTitle} onChange={(e) => setFormTitle(e.target.value)} className={inputStyle} /></div>
              <div><label className={labelStyle}>Mô tả</label><textarea value={formDesc} onChange={(e) => setFormDesc(e.target.value)} className={inputStyle} rows={3}></textarea></div>
              <div><label className={labelStyle}>Mức độ</label><select value={formSeverity} onChange={(e) => setFormSeverity(e.target.value as Severity)} className={inputStyle}><option value={Severity.LOW}>Thấp</option><option value={Severity.MEDIUM}>Trung bình</option><option value={Severity.HIGH}>KHẨN CẤP</option></select></div>
              <button type="submit" disabled={isSubmitting} className={`w-full bg-fkRed text-white font-bold py-3 rounded-lg shadow-lg ${isSubmitting ? 'opacity-50' : ''}`}>
                {isSubmitting ? 'Đang gửi...' : 'Gửi báo cáo'}
              </button>
            </form>
          </div>
        )}

        {activeTab === 'admin' && (
          <AdminPanel 
            branches={branches} 
            incidents={incidents} 
            onAddBranch={handleAddBranch}
            onUpdateBranch={handleUpdateBranch}
            onDeleteBranch={handleDeleteBranch}
            onDeleteIncident={handleDeleteIncident}
          />
        )}

        {activeTab === 'export' && <div className="p-10 text-center text-gray-400">Tính năng xuất file CSV đã tích hợp trong code chính.</div>}
      </main>

      {showConfigModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
            <h2 className="text-2xl font-bold mb-4">Cấu hình Supabase</h2>
            <div className="space-y-4">
              <input type="text" value={configUrl} onChange={(e) => setConfigUrl(e.target.value)} className="w-full border p-3 rounded" placeholder="Project URL" />
              <input type="password" value={configKey} onChange={(e) => setConfigKey(e.target.value)} className="w-full border p-3 rounded" placeholder="Anon Key" />
              {connectionError && <div className="text-red-500 text-xs">{connectionError}</div>}
              <div className="flex gap-2">
                <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 border rounded font-bold">Hủy</button>
                <button onClick={handleSaveConfig} className="flex-1 py-3 bg-green-600 text-white rounded font-bold">Kết nối</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
// Fix: Removed non-existent BRANCHES import from ../types
import { Incident, Severity, IncidentType, DeviceStatus } from '../types';
import WatermarkCamera from './WatermarkCamera';

interface IncidentCardProps {
  incident: Incident;
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
  // Fix: Added branchName prop to identify the branch for this incident
  branchName: string;
}

const IncidentCard: React.FC<IncidentCardProps> = ({ incident, onUpdate, branchName }) => {
  const isHighSeverity = incident.severity === Severity.HIGH;
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Resolution Popup State
  const [isResolvePopupOpen, setIsResolvePopupOpen] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  // Form State for Popup
  const [resolutionNote, setResolutionNote] = useState('');
  const [resolutionImages, setResolutionImages] = useState<string[]>([]);
  const [setupResponse, setSetupResponse] = useState('');
  const [deviceStatus, setDeviceStatus] = useState<DeviceStatus | ''>('');

  const [resolveError, setResolveError] = useState('');

  const images = incident.imageUrls || [];

  const [resViewerIndex, setResViewerIndex] = useState<number | null>(null);

  // Helper: Check if incident is related to equipment (Device or Game)
  const isEquipmentIssue = incident.type === IncidentType.DEVICE || incident.type === IncidentType.GAME;

  useEffect(() => {
    if (isResolvePopupOpen) {
      setResolutionNote(incident.resolutionNote || '');
      setResolutionImages(incident.resolutionImageUrls || []);
      setSetupResponse(incident.setupResponse || '');
      setDeviceStatus(incident.deviceStatus || '');
      setResolveError('');
    }
  }, [isResolvePopupOpen, incident]);

  const severityStyles = {
    [Severity.HIGH]: "bg-red-50 border-fkRed text-red-800 shadow-red-200",
    [Severity.MEDIUM]: "bg-yellow-50 border-yellow-500 text-yellow-800",
    [Severity.LOW]: "bg-green-50 border-green-500 text-green-800",
  };

  const badgeStyles = {
    [Severity.HIGH]: "bg-fkRed text-white animate-pulse",
    [Severity.MEDIUM]: "bg-yellow-500 text-white",
    [Severity.LOW]: "bg-green-500 text-white",
  };

  const deviceStatusLabels = {
    [DeviceStatus.UNSAFE]: 'Không an toàn',
    [DeviceStatus.BROKEN]: 'Hỏng hẳn',
    [DeviceStatus.WAITING_PARTS]: 'Chờ đồ thay',
    [DeviceStatus.FIXED]: 'Đã sửa',
  };

  const deviceStatusColors = {
    [DeviceStatus.UNSAFE]: 'bg-red-100 text-red-700 border-red-200',
    [DeviceStatus.BROKEN]: 'bg-gray-100 text-gray-700 border-gray-200',
    [DeviceStatus.WAITING_PARTS]: 'bg-orange-100 text-orange-700 border-orange-200',
    [DeviceStatus.FIXED]: 'bg-green-100 text-green-700 border-green-200',
  };

  const renderTypeBadge = () => {
    switch (incident.type) {
      case IncidentType.ACCIDENT:
        return (
          <span className="inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider border bg-rose-100 text-rose-800 border-rose-200">
            <i className="fas fa-user-injured mr-1"></i> Tai nạn
          </span>
        );
      case IncidentType.GAME:
        return (
          <span className="inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider border bg-purple-100 text-purple-800 border-purple-200">
            <i className="fas fa-gamepad mr-1"></i> Máy game
          </span>
        );
      case IncidentType.DEVICE:
      default:
        return (
          <span className="inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider border bg-indigo-100 text-indigo-800 border-indigo-200">
            <i className="fas fa-tools mr-1"></i> Thiết bị
          </span>
        );
    }
  };

  const handlePrev = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex(prev => (prev === 0 ? images.length - 1 : prev - 1));
  };

  const handleNext = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex(prev => (prev === images.length - 1 ? 0 : prev + 1));
  };

  const openModal = () => setIsModalOpen(true);
  const closeModal = () => setIsModalOpen(false);

  const handleZaloShare = (e: React.MouseEvent) => {
    e.stopPropagation();
    // Fix: Using the branchName prop directly instead of searching the non-existent BRANCHES list
    const message = `🚨 BÁO CÁO SỰ CỐ KHẨN CẤP 🚨\n📍 Tại: ${branchName}\n⚠️ Mức độ: NGHIÊM TRỌNG\n📝 Tiêu đề: ${incident.title}\n📄 Mô tả: ${incident.description}\n👤 Người báo: ${incident.reporterName} (${incident.reporterRole})`;
    navigator.clipboard.writeText(message).then(() => {
      alert("Đã copy nội dung báo cáo vào bộ nhớ tạm!\nVui lòng mở Zalo và dán (Paste) để gửi.");
    }).catch(err => {
      console.error('Failed to copy: ', err);
      alert("Không thể copy tự động. Vui lòng copy thủ công.");
    });
  };

  const handleSubmitUpdate = async () => {
    setResolveError('');
    setIsUpdating(true);

    try {
      if (incident.type === IncidentType.ACCIDENT) {
        if (!resolutionNote.trim()) {
          setResolveError('Vui lòng nhập nội dung xử lý.');
          setIsUpdating(false);
          return;
        }
        await onUpdate(incident.id, {
          isResolved: true,
          resolutionNote,
          resolutionImageUrls: resolutionImages
        });
        setIsResolvePopupOpen(false);
      } else if (isEquipmentIssue) {
        if (!deviceStatus) {
          setResolveError('Vui lòng chọn trạng thái thiết bị.');
          setIsUpdating(false);
          return;
        }

        if (deviceStatus === DeviceStatus.FIXED) {
          if (!resolutionNote.trim()) {
            setResolveError('Vui lòng nhập nội dung xử lý khi đã sửa xong.');
            setIsUpdating(false);
            return;
          }
          if (resolutionImages.length < 2) {
            setResolveError('Vui lòng tải lên ít nhất 2 hình ảnh sau xử lý.');
            setIsUpdating(false);
            return;
          }

          await onUpdate(incident.id, {
            isResolved: true,
            deviceStatus,
            setupResponse,
            resolutionNote,
            resolutionImageUrls: resolutionImages
          });
        } else {
          await onUpdate(incident.id, {
            isResolved: false,
            deviceStatus,
            setupResponse
          });
        }
        setIsResolvePopupOpen(false);
      }
    } catch (error) {
      setResolveError('Lỗi cập nhật. Vui lòng thử lại.');
    } finally {
      setIsUpdating(false);
    }
  };

  useEffect(() => {
    if (!isModalOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeModal();
      if (e.key === 'ArrowLeft') setCurrentImageIndex(prev => (prev === 0 ? images.length - 1 : prev - 1));
      if (e.key === 'ArrowRight') setCurrentImageIndex(prev => (prev === images.length - 1 ? 0 : prev + 1));
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isModalOpen, images.length]);

  return (
    <div className={`
      relative p-3 md:p-4 rounded-xl border-l-8 shadow-sm transition-all duration-300 h-full flex flex-col
      ${severityStyles[incident.severity]}
      ${isHighSeverity && !incident.isResolved ? 'animate-flash-red ring-2 ring-red-400 ring-offset-2' : 'bg-white'}
      ${incident.isResolved ? 'opacity-80' : ''}
    `}>
      <div className="flex justify-between items-start mb-2">
        <div className="flex-1 pr-2">
          <div className="flex flex-wrap gap-1.5 mb-1.5">
            <span className={`inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider ${badgeStyles[incident.severity]}`}>
              {incident.severity === Severity.HIGH && <i className="fas fa-exclamation-circle mr-1"></i>}
              {incident.severity === 'HIGH' ? 'Nghiêm trọng' : incident.severity === 'MEDIUM' ? 'TB' : 'Thấp'}
            </span>

            {renderTypeBadge()}

            {!incident.isResolved ? (
              isEquipmentIssue && incident.deviceStatus ? (
                 <span className={`inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider border ${deviceStatusColors[incident.deviceStatus]}`}>
                    {deviceStatusLabels[incident.deviceStatus]}
                 </span>
              ) : (
                <span className="inline-block px-1.5 py-0.5 rounded text-[10px] md:text-xs font-bold uppercase tracking-wider bg-gray-100 text-gray-600 border border-gray-300">
                  Chưa xử lý
                </span>
              )
            ) : null}
          </div>

          <h3 className="font-bold text-base md:text-lg leading-tight">{incident.title}</h3>
        </div>
        <div className="flex flex-col items-end flex-shrink-0">
          <span className="text-[10px] md:text-xs font-mono text-gray-500 bg-white/50 px-1.5 py-0.5 rounded whitespace-nowrap">
            {new Date(incident.timestamp).toLocaleTimeString('vi-VN', {hour: '2-digit', minute:'2-digit'})}
          </span>
          <span className="text-[10px] md:text-xs text-gray-400 mt-0.5">
            {new Date(incident.timestamp).toLocaleDateString('vi-VN', {day: '2-digit', month: '2-digit'})}
          </span>
        </div>
      </div>

      <p className="mb-3 text-sm leading-snug md:leading-relaxed whitespace-pre-line text-gray-800 flex-grow">{incident.description}</p>

      {!incident.isResolved && incident.setupResponse && (
        <div className="mb-3 text-xs bg-indigo-50 border border-indigo-100 p-2 rounded text-indigo-800 italic">
          <i className="fas fa-reply mr-1"></i> Setup: {incident.setupResponse}
        </div>
      )}

      <div className="flex justify-between items-center border-t border-black/5 pt-3 mt-1 gap-2">
        <div className="flex items-center gap-2">
          {!incident.isResolved ? (
            <button 
              onClick={(e) => { e.stopPropagation(); setIsResolvePopupOpen(true); }}
              className="px-3 py-1.5 bg-white border border-gray-300 rounded text-xs md:text-sm hover:bg-gray-50 font-bold text-gray-700 transition-colors shadow-sm active:bg-gray-100"
            >
              {isEquipmentIssue && incident.deviceStatus 
                ? <><i className="fas fa-edit mr-1 text-indigo-600"></i> Cập nhật</>
                : <><i className="fas fa-check-circle mr-1 text-green-600"></i> Xử lý</>
              }
            </button>
          ) : (
            <span className="text-green-700 font-bold text-xs md:text-sm flex items-center bg-green-50 px-2 py-1 rounded border border-green-100">
              <i className="fas fa-check mr-1"></i> Đã xử lý
            </span>
          )}

          {incident.severity === Severity.HIGH && !incident.isResolved && (
            <button
              onClick={handleZaloShare}
              className="px-3 py-1.5 bg-blue-600 border border-blue-600 rounded text-xs md:text-sm hover:bg-blue-700 font-bold text-white transition-colors shadow-sm active:bg-blue-800 flex items-center animate-bounce-short"
              title="Copy nội dung báo cáo"
            >
              <i className="fas fa-copy mr-1"></i> Copy Zalo
            </button>
          )}
        </div>

        <button 
          onClick={() => setIsExpanded(!isExpanded)} 
          className="text-gray-500 hover:text-indigo-600 flex items-center text-xs font-bold uppercase tracking-wide py-2 px-2 rounded active:bg-black/5 transition-colors"
        >
          {isExpanded ? 'Thu gọn' : 'Chi tiết'}
          <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'} ml-1.5`}></i>
        </button>
      </div>

      {isExpanded && (
        <div className="mt-3 pt-3 border-t border-black/5 animate-fade-in">
          <div className="mb-4 flex items-center text-sm text-gray-700 bg-white/40 p-2 rounded">
             <i className="fas fa-user-circle text-2xl mr-3 opacity-60"></i>
             <div>
                <span className="font-bold block text-gray-900">{incident.reporterName}</span>
                <span className="text-xs opacity-80 uppercase tracking-wide">{incident.reporterRole}</span>
             </div>
          </div>

          {images.length > 0 ? (
            <div className="mb-4">
              <h4 className="text-[10px] md:text-xs font-bold uppercase text-gray-500 mb-2">Hình ảnh hiện trường ({images.length})</h4>
              <div className="relative rounded-lg overflow-hidden border border-black/10 bg-gray-100 aspect-video group cursor-zoom-in" onClick={openModal}>
                <img src={images[currentImageIndex]} alt={`Evidence ${currentImageIndex + 1}`} className="w-full h-full object-cover transition-opacity duration-300" />
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors"></div>
                {images.length > 1 && (
                  <>
                    <button onClick={handlePrev} className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full bg-black/40 text-white flex items-center justify-center transition-all opacity-100 md:opacity-0 md:group-hover:opacity-100 transform active:scale-95"><i className="fas fa-chevron-left"></i></button>
                    <button onClick={handleNext} className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full bg-black/40 text-white flex items-center justify-center transition-all opacity-100 md:opacity-0 md:group-hover:opacity-100 transform active:scale-95"><i className="fas fa-chevron-right"></i></button>
                    <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex space-x-1.5 z-10">
                      {images.map((_, idx) => (
                        <div key={idx} className={`w-1.5 h-1.5 rounded-full shadow-sm transition-all ${idx === currentImageIndex ? 'bg-white scale-125' : 'bg-white/50'}`}></div>
                      ))}
                    </div>
                  </>
                )}
                <div className="absolute top-2 right-2 bg-black/60 text-white text-[10px] px-2 py-0.5 rounded-full backdrop-blur-sm font-bold tracking-wide">{currentImageIndex + 1}/{images.length}</div>
              </div>
            </div>
          ) : (
            <div className="mb-4 text-sm text-gray-500 italic bg-gray-50 p-2 rounded text-center">Không có hình ảnh đính kèm.</div>
          )}

          {incident.isResolved && incident.resolutionNote && (
            <div className="mt-4 bg-green-50/80 rounded-lg p-3 border border-green-200">
              <h4 className="font-bold text-green-800 text-sm mb-2 flex items-center"><i className="fas fa-check-circle mr-2"></i> Kết quả xử lý</h4>
              <p className="text-sm text-gray-800 mb-3 whitespace-pre-line">{incident.resolutionNote}</p>
              {incident.resolutionImageUrls && incident.resolutionImageUrls.length > 0 && (
                <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
                  {incident.resolutionImageUrls.map((url, idx) => (
                    <div key={idx} className="aspect-square rounded overflow-hidden border border-gray-200 cursor-pointer active:opacity-80" onClick={() => setResViewerIndex(idx)}>
                      <img src={url} alt="Resolved" className="w-full h-full object-cover" />
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
