        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <input
              type="password"
              autoFocus
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className={`w-full border-2 rounded-xl p-3 text-center text-2xl tracking-[1em] focus:outline-none transition-colors ${error ? 'border-red-500 bg-red-50' : 'border-gray-200 focus:border-indigo-500'}`}
              placeholder="••••"
            />
            {error && <p className="text-red-500 text-xs text-center mt-2 font-bold animate-pulse">Mật khẩu không chính xác!</p>}
