            <button
              type="button"
              onClick={onClose}
              className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-100 rounded-xl transition-colors"
            >
              Hủy
            </button>
            <button
              type="submit"
              className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
            >
              Xác nhận
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AdminLoginModal;

import React, { useState, useEffect, useRef } from 'react';
import { Branch, Incident, Severity, IncidentType, DeviceStatus, DEFAULT_BRANCHES } from './types';
import IncidentCard from './components/IncidentCard';
import WatermarkCamera from './components/WatermarkCamera';
import AdminPanel from './components/AdminPanel';
import AdminLoginModal from './components/AdminLoginModal';
import { playAlertSound } from './utils';
import { getSupabase, initSupabase, resetSupabaseConfig } from './utils/supabaseClient';
import { RealtimeChannel } from '@supabase/supabase-js';

// --- SUB-COMPONENT: Branch Section ---
interface BranchSectionProps {
  branch: Branch;
  incidents: Incident[];
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
}

const BranchSection: React.FC<BranchSectionProps> = ({ branch, incidents, onUpdate }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const sortedIncidents = [...incidents].sort((a, b) => {
    const severityScore = { [Severity.HIGH]: 3, [Severity.MEDIUM]: 2, [Severity.LOW]: 1 };
    const scoreA = severityScore[a.severity] || 0;
    const scoreB = severityScore[b.severity] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    return b.timestamp - a.timestamp;
  });

  const visibleIncidents = isExpanded ? sortedIncidents : sortedIncidents.slice(0, 3);
  const hiddenCount = sortedIncidents.length - 3;
  const hasMore = sortedIncidents.length > 3;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-6 transition-all duration-300">
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-fkPurple rounded-full"></div>
          <h2 className="text-base md:text-lg font-bold text-gray-800">{branch.name}</h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{incidents.length}</span>
        </div>
        {hasMore && (
           <button onClick={() => setIsExpanded(!isExpanded)} className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center transition-colors px-2 py-1 rounded hover:bg-indigo-50">
             {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sự cố`}
             <i className={`fas fa-chevron-${isExpanded ? 'up' : 'right'} ml-1.5`}></i>
           </button>
        )}
      </div>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-6">
        {visibleIncidents.map(incident => (
          <IncidentCard 
            key={incident.id} 
            incident={incident} 
            onUpdate={onUpdate} 
            branchName={branch.name}
          />
        ))}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'report' | 'export' | 'admin'>('dashboard');
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<string>('all');
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<'all' | 'unresolved' | 'resolved'>('unresolved');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState<'all' | IncidentType>('all');
  const [isMuted, setIsMuted] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [connectionError, setConnectionError] = useState('');

  const subscriptionRef = useRef<RealtimeChannel | null>(null);

  // Logic điều hướng Tab
  const navigateTo = (tab: 'dashboard' | 'report' | 'export' | 'admin') => {
    if (tab === 'admin' && !isAdminAuthenticated) {
      setShowAdminLogin(true);
      return;
    }
    setActiveTab(tab);
    window.location.hash = tab;
  };

  // Đồng bộ URL Hash
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '');
      if (hash === 'admin') {
        if (!isAdminAuthenticated) setShowAdminLogin(true);
        else setActiveTab('admin');
      } else if (['dashboard', 'report', 'export'].includes(hash)) {
        setActiveTab(hash as any);
      }
    };
    handleHashChange();
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isAdminAuthenticated]);

  useEffect(() => {
    const sb = getSupabase();
    if (sb) {
      setIsConfigured(true);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    }
    return () => { if (subscriptionRef.current) subscriptionRef.current.unsubscribe(); };
  }, []);

  const setupRealtime = (sb: any) => {
    if (subscriptionRef.current) subscriptionRef.current.unsubscribe();
    subscriptionRef.current = sb.channel('all-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'incidents' }, () => { fetchIncidents(); playAlertSound(); })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, () => { fetchBranches(); })
      .subscribe();
  };

  const handleSaveConfig = () => {
    try {
      setConnectionError('');
      const sb = initSupabase(configUrl.trim(), configKey.trim());
      setIsConfigured(true);
      setShowConfigModal(false);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } catch (e) { setConnectionError('Cấu hình không hợp lệ.'); }
  };

  const fetchBranches = async () => {
    const sb = getSupabase();
    if (!sb) return;
    const { data, error } = await sb.from('branches').select('*').order('name');
    if (!error && data) setBranches(data);
  };

  const fetchIncidents = async () => {
    const sb = getSupabase();
    if (!sb) return;
    setIsLoading(true);
    const { data, error } = await sb.from('incidents').select('*').order('timestamp', { ascending: false });
    if (!error) { setIncidents(data || []); }
    setIsLoading(false);
  };

  // Admin Actions
  const handleAddBranch = async (name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').insert([{ name }]);
    fetchBranches();
  };

  const handleUpdateBranch = async (id: string, name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').update({ name }).eq('id', id);
    fetchBranches();
  };

  const handleDeleteBranch = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').delete().eq('id', id);
    fetchBranches();
  };

  const handleDeleteIncident = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('incidents').delete().eq('id', id);
    fetchIncidents();
  };

  // Audio Logic
  useEffect(() => {
    const hasActiveHighSeverity = incidents.some(i => i.severity === Severity.HIGH && !i.isResolved);
    let interval: number;
    if (hasActiveHighSeverity && !isMuted) {
      playAlertSound();
      interval = window.setInterval(playAlertSound, 5000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [incidents, isMuted]);

  // Form State
  const [formBranchId, setFormBranchId] = useState('');
  useEffect(() => { if (branches.length > 0 && !formBranchId) setFormBranchId(branches[0].id); }, [branches]);

  const [formType, setFormType] = useState<IncidentType>(IncidentType.DEVICE);
  const [formTitle, setFormTitle] = useState('');
  const [formDesc, setFormDesc] = useState('');
  const [formSeverity, setFormSeverity] = useState<Severity>(Severity.LOW);
  const [formImages, setFormImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formReporterName, setFormReporterName] = useState('');
  const [formReporterRole, setFormReporterRole] = useState('');

  const uploadImage = async (base64Image: string): Promise<string | null> => {
    const sb = getSupabase();
    if (!sb) return null;
    try {
      const base64Str = base64Image.split(',')[1];
      const byteCharacters = atob(base64Str);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'image/jpeg' });
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.jpg`;
      const { data, error } = await sb.storage.from('incident-images').upload(fileName, blob, { contentType: 'image/jpeg' });
      if (error) return null;
      const { data: { publicUrl } } = sb.storage.from('incident-images').getPublicUrl(fileName);
      return publicUrl;
    } catch { return null; }
  };

  const handleUpdateIncident = async (id: string, updates: Partial<Incident>) => {
    const sb = getSupabase();
    if (!sb) return;
    let finalUpdates = { ...updates };
    if (updates.resolutionImageUrls) {
       const uploaded = await Promise.all(updates.resolutionImageUrls.map(async img => img.startsWith('data:') ? await uploadImage(img) : img));
       finalUpdates.resolutionImageUrls = uploaded.filter(u => u !== null) as string[];
    }
    await sb.from('incidents').update(finalUpdates).eq('id', id);
    fetchIncidents();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sb = getSupabase();
    if (!sb) { setShowConfigModal(true); return; }
    if (!formReporterName || !formReporterRole || !formBranchId) { alert('Vui lòng điền đủ thông tin'); return; }
    setIsSubmitting(true);
    const uploadedImageUrls: string[] = [];
    for (const base64 of formImages) { const url = await uploadImage(base64); if (url) uploadedImageUrls.push(url); }
    const { error } = await sb.from('incidents').insert([{
      branchId: formBranchId, title: formTitle, description: formDesc, severity: formSeverity, type: formType,
      timestamp: Date.now(), imageUrls: uploadedImageUrls, reporterName: formReporterName, reporterRole: formReporterRole, isResolved: false
    }]);
    setIsSubmitting(false);
    if (!error) { fetchIncidents(); setFormTitle(''); setFormDesc(''); setFormImages([]); navigateTo('dashboard'); }
  };

  const filteredIncidents = incidents.filter(i => {
    const bMatch = selectedBranchFilter === 'all' || i.branchId === selectedBranchFilter;
    const sMatch = selectedStatusFilter === 'all' ? true : selectedStatusFilter === 'resolved' ? i.isResolved : !i.isResolved;
    const tMatch = selectedTypeFilter === 'all' || i.type === selectedTypeFilter;
    return bMatch && sMatch && tMatch;
  });

  const inputStyle = "w-full rounded-lg border border-indigo-500 bg-white text-black text-base p-3 focus:border-indigo-700 focus:ring-2 focus:ring-indigo-200 outline-none transition-all placeholder-gray-400 font-medium appearance-none";
  const labelStyle = "block text-sm font-bold text-gray-700 mb-2";

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-gradient-to-r from-fkRed to-fkPurple text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-screen-xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center space-x-3 cursor-pointer" onClick={() => navigateTo('dashboard')}>
            <div className="bg-white/20 p-2 rounded-full"><i className="fas fa-child text-xl md:text-2xl"></i></div>
            <div><h1 className="text-lg md:text-xl font-bold tracking-tight">FunnyKids</h1><span className="text-xs font-light opacity-80">Incident Manager</span></div>
          </div>
          <div className="flex items-center gap-1.5 md:gap-2">
            <button 
              onClick={() => navigateTo('admin')} 
              className={`p-2 rounded-lg border transition-all flex items-center gap-2 ${activeTab === 'admin' ? 'bg-white text-indigo-600 border-white' : 'bg-white/10 text-white border-white/20 hover:bg-white/20'}`}
              title="Quản trị hệ thống"
            >
              <i className="fas fa-user-shield"></i>
              <span className="text-[10px] font-bold hidden sm:inline uppercase tracking-wider">Admin</span>
            </button>
            <button onClick={() => setShowConfigModal(true)} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 border border-white/20 transition-all"><i className="fas fa-cog"></i></button>
            <button onClick={() => setIsMuted(!isMuted)} className={`flex items-center gap-2 px-3 py-2 rounded-lg border ${isMuted ? 'bg-red-500/20 text-red-100 border-red-400/50' : 'bg-white/10 text-white border-white/20'}`}>
              <i className={`fas ${isMuted ? 'fa-volume-mute' : 'fa-volume-up'}`}></i><span className="text-xs font-bold hidden md:inline">{isMuted ? 'Muted' : 'Sound'}</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="bg-white shadow-sm border-b sticky top-[60px] z-40">
        <div className="max-w-screen-xl mx-auto flex">
          <button onClick={() => navigateTo('dashboard')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'dashboard' ? 'border-fkPurple text-fkPurple bg-indigo-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-th-large"></i></div>Theo dõi
          </button>
          <button onClick={() => navigateTo('report')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'report' ? 'border-fkRed text-fkRed bg-red-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-plus-circle"></i></div>Báo cáo
          </button>
          <button onClick={() => navigateTo('export')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'export' ? 'border-green-600 text-green-600 bg-green-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-file-export"></i></div>Xuất file
          </button>
        </div>
      </nav>

      <main className="flex-grow max-w-screen-xl w-full mx-auto px-4 py-6">
        {activeTab === 'dashboard' && (
          <div className="space-y-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-4">
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Trạng thái</label>
               <select value={selectedStatusFilter} onChange={(e) => setSelectedStatusFilter(e.target.value as any)} className={inputStyle}><option value="unresolved">Chưa xử lý</option><option value="resolved">Đã xử lý</option><option value="all">Tất cả</option></select></div>
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Loại sự cố</label>
               <select value={selectedTypeFilter} onChange={(e) => setSelectedTypeFilter(e.target.value as any)} className={inputStyle}><option value="all">Tất cả loại</option><option value={IncidentType.DEVICE}>Thiết bị</option><option value={IncidentType.GAME}>Máy game</option><option value={IncidentType.ACCIDENT}>Tai nạn</option></select></div>
               <div><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Chi nhánh</label>
               <select value={selectedBranchFilter} onChange={(e) => setSelectedBranchFilter(e.target.value)} className={inputStyle}><option value="all">Tất cả chi nhánh</option>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
            </div>
            {isLoading ? <div className="text-center py-20 text-gray-300"><i className="fas fa-circle-notch fa-spin text-4xl mb-2"></i><p>Đang tải dữ liệu...</p></div> : 
              branches.filter(b => selectedBranchFilter === 'all' || b.id === selectedBranchFilter).map(branch => {
                const bIncidents = filteredIncidents.filter(i => i.branchId === branch.id);
                return bIncidents.length > 0 ? <BranchSection key={branch.id} branch={branch} incidents={bIncidents} onUpdate={handleUpdateIncident} /> : null;
              })
            }
          </div>
        )}

        {activeTab === 'report' && (
          <div className="max-w-3xl mx-auto bg-white rounded-xl shadow-lg p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-6 border-b pb-4">Báo cáo sự cố mới</h2>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(t => (
                  <div key={t} onClick={() => setFormType(t)} className={`cursor-pointer border-2 p-4 rounded-lg flex flex-col items-center transition-all ${formType === t ? 'border-fkPurple bg-indigo-50 text-indigo-700' : 'border-gray-100'}`}>
                    <i className={`fas ${t === IncidentType.DEVICE ? 'fa-tools' : t === IncidentType.GAME ? 'fa-gamepad' : 'fa-user-injured'} text-2xl mb-2`}></i>
                    <span className="font-bold text-sm">{t === IncidentType.DEVICE ? 'Thiết bị' : t === IncidentType.GAME ? 'Máy game' : 'Tai nạn'}</span>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className={labelStyle}>Người báo <span className="text-red-500">*</span></label><input type="text" required value={formReporterName} onChange={(e) => setFormReporterName(e.target.value)} className={inputStyle} /></div>
                <div><label className={labelStyle}>Chức vụ <span className="text-red-500">*</span></label><input type="text" required value={formReporterRole} onChange={(e) => setFormReporterRole(e.target.value)} className={inputStyle} /></div>
              </div>
              <div><label className={labelStyle}>Chi nhánh <span className="text-red-500">*</span></label><select value={formBranchId} onChange={(e) => setFormBranchId(e.target.value)} className={inputStyle}>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
              <div><label className={labelStyle}>Hình ảnh</label><WatermarkCamera images={formImages} onImagesChange={setFormImages} /></div>
              <div><label className={labelStyle}>Tiêu đề <span className="text-red-500">*</span></label><input type="text" required value={formTitle} onChange={(e) => setFormTitle(e.target.value)} className={inputStyle} /></div>
              <div><label className={labelStyle}>Mô tả</label><textarea value={formDesc} onChange={(e) => setFormDesc(e.target.value)} className={inputStyle} rows={3}></textarea></div>
              <div><label className={labelStyle}>Mức độ</label><select value={formSeverity} onChange={(e) => setFormSeverity(e.target.value as Severity)} className={inputStyle}><option value={Severity.LOW}>Thấp</option><option value={Severity.MEDIUM}>Trung bình</option><option value={Severity.HIGH}>KHẨN CẤP</option></select></div>
              <button type="submit" disabled={isSubmitting} className={`w-full bg-fkRed text-white font-bold py-3 rounded-lg shadow-lg ${isSubmitting ? 'opacity-50' : ''}`}>
                {isSubmitting ? 'Đang gửi...' : 'Gửi báo cáo'}
              </button>
            </form>
          </div>
        )}

        {activeTab === 'admin' && isAdminAuthenticated && (
          <AdminPanel 
            branches={branches} 
            incidents={incidents} 
            onAddBranch={handleAddBranch}
            onUpdateBranch={handleUpdateBranch}
            onDeleteBranch={handleDeleteBranch}
            onDeleteIncident={handleDeleteIncident}
          />
        )}

        {activeTab === 'export' && <div className="p-10 text-center text-gray-400">Tính năng xuất file CSV đã tích hợp trong code chính.</div>}
      </main>

      <AdminLoginModal 
        isOpen={showAdminLogin} 
        onClose={() => setShowAdminLogin(false)} 
        onSuccess={() => {
          setIsAdminAuthenticated(true);
          setShowAdminLogin(false);
          setActiveTab('admin');
          window.location.hash = 'admin';
        }}
      />

      {showConfigModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
            <h2 className="text-2xl font-bold mb-4">Cấu hình Supabase</h2>
            <div className="space-y-4">
              <input type="text" value={configUrl} onChange={(e) => setConfigUrl(e.target.value)} className="w-full border p-3 rounded" placeholder="Project URL" />
              <input type="password" value={configKey} onChange={(e) => setConfigKey(e.target.value)} className="w-full border p-3 rounded" placeholder="Anon Key" />
              {connectionError && <div className="text-red-500 text-xs">{connectionError}</div>}
              <div className="flex gap-2">
                <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 border rounded font-bold">Hủy</button>
                <button onClick={handleSaveConfig} className="flex-1 py-3 bg-green-600 text-white rounded font-bold">Kết nối</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Branch, Incident, Severity, IncidentType, DeviceStatus } from './types';
import IncidentCard from './components/IncidentCard';
import WatermarkCamera from './components/WatermarkCamera';
import AdminPanel from './components/AdminPanel';
import AdminLoginModal from './components/AdminLoginModal';
import { playAlertSound } from './utils';
import { getSupabase, initSupabase } from './utils/supabaseClient';
import { RealtimeChannel } from '@supabase/supabase-js';

// --- SUB-COMPONENT: Branch Section ---
interface BranchSectionProps {
  branch: Branch;
  incidents: Incident[];
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
}

const BranchSection: React.FC<BranchSectionProps> = ({ branch, incidents, onUpdate }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const sortedIncidents = [...incidents].sort((a, b) => {
    const severityScore = { [Severity.HIGH]: 3, [Severity.MEDIUM]: 2, [Severity.LOW]: 1 };
    const scoreA = severityScore[a.severity] || 0;
    const scoreB = severityScore[b.severity] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    return b.timestamp - a.timestamp;
  });

  const visibleIncidents = isExpanded ? sortedIncidents : sortedIncidents.slice(0, 3);
  const hiddenCount = sortedIncidents.length - 3;
  const hasMore = sortedIncidents.length > 3;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-6 animate-fade-in">
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-fkPurple rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]"></div>
          <h2 className="text-base md:text-lg font-bold text-gray-800">{branch.name}</h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{incidents.length}</span>
        </div>
        {hasMore && (
           <button onClick={() => setIsExpanded(!isExpanded)} className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center transition-colors px-2 py-1 rounded hover:bg-indigo-50">
             {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sự cố`}
             <i className={`fas fa-chevron-${isExpanded ? 'up' : 'right'} ml-1.5`}></i>
           </button>
        )}
      </div>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-6">
        {visibleIncidents.map(incident => (
          <IncidentCard 
            key={incident.id} 
            incident={incident} 
            onUpdate={onUpdate} 
            branchName={branch.name}
          />
        ))}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'report' | 'export' | 'admin'>('dashboard');
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<string>('all');
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<'all' | 'unresolved' | 'resolved'>('unresolved');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState<'all' | IncidentType>('all');
  const [isMuted, setIsMuted] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [connectionError, setConnectionError] = useState('');

  const subscriptionRef = useRef<RealtimeChannel | null>(null);

  // Helper: Chuẩn hóa dữ liệu từ snake_case sang camelCase
  const normalizeIncident = (data: any): Incident => {
    return {
      id: data.id,
      branchId: data.branch_id || data.branchId,
      title: data.title,
      description: data.description,
      severity: data.severity,
      type: data.type,
      timestamp: data.timestamp ? Number(data.timestamp) : Date.now(),
      imageUrls: data.image_urls || data.imageUrls || [],
      reporterName: data.reporter_name || data.reporterName || 'N/A',
      reporterRole: data.reporter_role || data.reporterRole || 'Staff',
      isResolved: data.is_resolved !== undefined ? data.is_resolved : data.isResolved,
      deviceStatus: data.device_status || data.deviceStatus,
      setupResponse: data.setup_response || data.setupResponse,
      resolutionNote: data.resolution_note || data.resolutionNote,
      resolutionImageUrls: data.resolution_image_urls || data.resolutionImageUrls || []
    };
  };

  const navigateTo = (tab: 'dashboard' | 'report' | 'export' | 'admin') => {
    if (tab === 'admin' && !isAdminAuthenticated) {
      setShowAdminLogin(true);
      return;
    }
    setActiveTab(tab);
    window.location.hash = tab;
  };

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '');
      if (hash === 'admin') {
        if (!isAdminAuthenticated) setShowAdminLogin(true);
        else setActiveTab('admin');
      } else if (['dashboard', 'report', 'export'].includes(hash)) {
        setActiveTab(hash as any);
      }
    };
    handleHashChange();
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isAdminAuthenticated]);

  useEffect(() => {
    const sb = getSupabase();
    if (sb) {
      setIsConfigured(true);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } else {
      setShowConfigModal(true);
    }
    return () => { if (subscriptionRef.current) subscriptionRef.current.unsubscribe(); };
  }, []);

  const setupRealtime = (sb: any) => {
    if (subscriptionRef.current) subscriptionRef.current.unsubscribe();
    subscriptionRef.current = sb.channel('all-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'incidents' }, () => { fetchIncidents(); playAlertSound(); })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, () => { fetchBranches(); })
      .subscribe();
  };

  const handleSaveConfig = () => {
    try {
      setConnectionError('');
      const sb = initSupabase(configUrl.trim(), configKey.trim());
      setIsConfigured(true);
      setShowConfigModal(false);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } catch (e) { setConnectionError('Cấu hình không hợp lệ.'); }
  };

  const fetchBranches = async () => {
    const sb = getSupabase();
    if (!sb) return;
    const { data, error } = await sb.from('branches').select('*').order('name');
    if (!error && data) setBranches(data);
  };

  const fetchIncidents = async () => {
    const sb = getSupabase();
    if (!sb) return;
    setIsLoading(true);
    const { data, error } = await sb.from('incidents').select('*').order('timestamp', { ascending: false });
    if (!error && data) {
      setIncidents(data.map(normalizeIncident));
    } else if (error) {
      console.error("Fetch Error:", error);
    }
    setIsLoading(false);
  };

  // Admin Actions
  const handleAddBranch = async (name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').insert([{ name }]);
    fetchBranches();
  };

  const handleUpdateBranch = async (id: string, name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').update({ name }).eq('id', id);
    fetchBranches();
  };

  const handleDeleteBranch = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').delete().eq('id', id);
    fetchBranches();
  };

  const handleDeleteIncident = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('incidents').delete().eq('id', id);
    fetchIncidents();
  };

  // Audio Logic
  useEffect(() => {
    const hasActiveHighSeverity = incidents.some(i => i.severity === Severity.HIGH && !i.isResolved);
    let interval: number;
    if (hasActiveHighSeverity && !isMuted) {
      playAlertSound();
      interval = window.setInterval(playAlertSound, 5000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [incidents, isMuted]);

  // Form State
  const [formBranchId, setFormBranchId] = useState('');
  useEffect(() => { if (branches.length > 0 && !formBranchId) setFormBranchId(branches[0].id); }, [branches]);

  const [formType, setFormType] = useState<IncidentType>(IncidentType.DEVICE);
  const [formTitle, setFormTitle] = useState('');
  const [formDesc, setFormDesc] = useState('');
  const [formSeverity, setFormSeverity] = useState<Severity>(Severity.LOW);
  const [formImages, setFormImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formReporterName, setFormReporterName] = useState('');
  const [formReporterRole, setFormReporterRole] = useState('');

  const uploadImage = async (base64Image: string): Promise<string | null> => {
    const sb = getSupabase();
    if (!sb) return null;
    try {
      const base64Str = base64Image.split(',')[1];
      const byteCharacters = atob(base64Str);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'image/jpeg' });
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.jpg`;
      const { data, error } = await sb.storage.from('incident-images').upload(fileName, blob, { contentType: 'image/jpeg' });
      if (error) return null;
      const { data: { publicUrl } } = sb.storage.from('incident-images').getPublicUrl(fileName);
      return publicUrl;
    } catch { return null; }
  };

  const handleUpdateIncident = async (id: string, updates: Partial<Incident>) => {
    const sb = getSupabase();
    if (!sb) return;

    // Mapping back to snake_case for DB update if necessary
    const dbUpdates: any = { ...updates };
    if (updates.isResolved !== undefined) dbUpdates.is_resolved = updates.isResolved;
    if (updates.deviceStatus) dbUpdates.device_status = updates.deviceStatus;
    if (updates.setupResponse) dbUpdates.setup_response = updates.setupResponse;
    if (updates.resolutionNote) dbUpdates.resolution_note = updates.resolutionNote;

    if (updates.resolutionImageUrls) {
       const uploaded = await Promise.all(updates.resolutionImageUrls.map(async img => img.startsWith('data:') ? await uploadImage(img) : img));
       dbUpdates.resolution_image_urls = uploaded.filter(u => u !== null) as string[];
    }

    await sb.from('incidents').update(dbUpdates).eq('id', id);
    fetchIncidents();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sb = getSupabase();
    if (!sb) { setShowConfigModal(true); return; }
    if (!formReporterName || !formReporterRole || !formBranchId) { alert('Vui lòng điền đủ thông tin'); return; }
    setIsSubmitting(true);
    const uploadedImageUrls: string[] = [];
    for (const base64 of formImages) { const url = await uploadImage(base64); if (url) uploadedImageUrls.push(url); }

    const { error } = await sb.from('incidents').insert([{
      branch_id: formBranchId, 
      title: formTitle, 
      description: formDesc, 
      severity: formSeverity, 
      type: formType,
      timestamp: Date.now(), 
      image_urls: uploadedImageUrls, 
      reporter_name: formReporterName, 
      reporter_role: formReporterRole, 
      is_resolved: false
    }]);

    setIsSubmitting(false);
    if (!error) { fetchIncidents(); setFormTitle(''); setFormDesc(''); setFormImages([]); navigateTo('dashboard'); }
  };

  const filteredIncidents = incidents.filter(i => {
    const bMatch = selectedBranchFilter === 'all' || i.branchId === selectedBranchFilter;
    const sMatch = selectedStatusFilter === 'all' ? true : selectedStatusFilter === 'resolved' ? i.isResolved : !i.isResolved;
    const tMatch = selectedTypeFilter === 'all' || i.type === selectedTypeFilter;
    return bMatch && sMatch && tMatch;
  });

  const branchesWithIncidents = branches.filter(b => {
    const hasMatch = filteredIncidents.some(i => i.branchId === b.id);
    const matchesFilter = selectedBranchFilter === 'all' || b.id === selectedBranchFilter;
    return matchesFilter && hasMatch;
  });

  const inputStyle = "w-full rounded-lg border border-indigo-500 bg-white text-black text-base p-3 focus:border-indigo-700 focus:ring-2 focus:ring-indigo-200 outline-none transition-all placeholder-gray-400 font-medium appearance-none";
  const labelStyle = "block text-sm font-bold text-gray-700 mb-2";

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-gradient-to-r from-fkRed to-fkPurple text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-screen-xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center space-x-3 cursor-pointer group" onClick={() => navigateTo('dashboard')}>
            <div className="bg-white/20 p-2 rounded-full group-hover:bg-white/30 transition-colors"><i className="fas fa-child text-xl md:text-2xl"></i></div>
            <div><h1 className="text-lg md:text-xl font-bold tracking-tight">FunnyKids</h1><span className="text-xs font-light opacity-80">Incident Manager</span></div>
          </div>
          <div className="flex items-center gap-1.5 md:gap-2">
            <button 
              onClick={() => navigateTo('admin')} 
              className={`p-2 rounded-lg border transition-all flex items-center gap-2 ${activeTab === 'admin' ? 'bg-white text-indigo-600 border-white' : 'bg-white/10 text-white border-white/20 hover:bg-white/20'}`}
              title="Quản trị hệ thống"
            >
              <i className="fas fa-user-shield"></i>
              <span className="text-[10px] font-bold hidden sm:inline uppercase tracking-wider">Admin</span>
            </button>
            <button onClick={() => setShowConfigModal(true)} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 border border-white/20 transition-all"><i className="fas fa-cog"></i></button>
            <button onClick={() => setIsMuted(!isMuted)} className={`flex items-center gap-2 px-3 py-2 rounded-lg border ${isMuted ? 'bg-red-500/20 text-red-100 border-red-400/50' : 'bg-white/10 text-white border-white/20'}`}>
              <i className={`fas ${isMuted ? 'fa-volume-mute' : 'fa-volume-up'}`}></i><span className="text-xs font-bold hidden md:inline">{isMuted ? 'Muted' : 'Sound'}</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="bg-white shadow-sm border-b sticky top-[60px] z-40">
        <div className="max-w-screen-xl mx-auto flex">
          <button onClick={() => navigateTo('dashboard')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'dashboard' ? 'border-fkPurple text-fkPurple bg-indigo-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-th-large"></i></div>Theo dõi
          </button>
          <button onClick={() => navigateTo('report')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'report' ? 'border-fkRed text-fkRed bg-red-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-plus-circle"></i></div>Báo cáo
          </button>
          <button onClick={() => navigateTo('export')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'export' ? 'border-green-600 text-green-600 bg-green-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-file-export"></i></div>Xuất file
          </button>
        </div>
      </nav>

      <main className="flex-grow max-w-screen-xl w-full mx-auto px-4 py-6">
        {activeTab === 'dashboard' && (
          <div className="space-y-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-col md:flex-row gap-4 items-end">
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Trạng thái</label>
               <select value={selectedStatusFilter} onChange={(e) => setSelectedStatusFilter(e.target.value as any)} className={inputStyle}><option value="unresolved">Chưa xử lý</option><option value="resolved">Đã xử lý</option><option value="all">Tất cả</option></select></div>
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Loại sự cố</label>
               <select value={selectedTypeFilter} onChange={(e) => setSelectedTypeFilter(e.target.value as any)} className={inputStyle}><option value="all">Tất cả loại</option><option value={IncidentType.DEVICE}>Thiết bị</option><option value={IncidentType.GAME}>Máy game</option><option value={IncidentType.ACCIDENT}>Tai nạn</option></select></div>
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Chi nhánh</label>
               <select value={selectedBranchFilter} onChange={(e) => setSelectedBranchFilter(e.target.value)} className={inputStyle}><option value="all">Tất cả chi nhánh</option>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
               <button onClick={fetchIncidents} className="p-3 bg-indigo-50 text-indigo-600 rounded-lg border border-indigo-200 hover:bg-indigo-100 transition-colors" title="Làm mới"><i className={`fas fa-sync-alt ${isLoading ? 'fa-spin' : ''}`}></i></button>
            </div>

            {isLoading ? (
              <div className="text-center py-20 animate-pulse">
                <i className="fas fa-circle-notch fa-spin text-4xl text-indigo-400 mb-2"></i>
                <p className="text-gray-400 font-medium">Đang tải dữ liệu...</p>
              </div>
            ) : branchesWithIncidents.length > 0 ? (
              branchesWithIncidents.map(branch => {
                const bIncidents = filteredIncidents.filter(i => i.branchId === branch.id);
                return <BranchSection key={branch.id} branch={branch} incidents={bIncidents} onUpdate={handleUpdateIncident} />;
              })
            ) : (
              <div className="text-center py-20 bg-white rounded-2xl border-2 border-dashed border-gray-200 animate-fade-in">
                <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-search text-gray-300 text-4xl"></i>
                </div>
                <h3 className="text-lg font-bold text-gray-700">Không tìm thấy sự cố nào</h3>
                <p className="text-gray-500 max-w-xs mx-auto mt-2 text-sm">Vui lòng kiểm tra lại bộ lọc hoặc đảm bảo dữ liệu trong database đã được nhập đúng định dạng.</p>
                <button onClick={() => { setSelectedStatusFilter('all'); setSelectedBranchFilter('all'); setSelectedTypeFilter('all'); }} className="mt-6 text-indigo-600 font-bold hover:underline text-sm">Xóa tất cả bộ lọc</button>
              </div>
            )}
          </div>
        )}

        {activeTab === 'report' && (
          <div className="max-w-3xl mx-auto bg-white rounded-xl shadow-lg p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-6 border-b pb-4 flex items-center">
              <i className="fas fa-edit mr-3 text-fkRed"></i> Báo cáo sự cố mới
            </h2>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(t => (
                  <div key={t} onClick={() => setFormType(t)} className={`cursor-pointer border-2 p-4 rounded-lg flex flex-col items-center transition-all ${formType === t ? 'border-fkPurple bg-indigo-50 text-indigo-700' : 'border-gray-100 bg-gray-50/30'}`}>
                    <i className={`fas ${t === IncidentType.DEVICE ? 'fa-tools' : t === IncidentType.GAME ? 'fa-gamepad' : 'fa-user-injured'} text-2xl mb-2`}></i>
                    <span className="font-bold text-sm">{t === IncidentType.DEVICE ? 'Thiết bị' : t === IncidentType.GAME ? 'Máy game' : 'Tai nạn'}</span>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className={labelStyle}>Người báo <span className="text-red-500">*</span></label><input type="text" required value={formReporterName} onChange={(e) => setFormReporterName(e.target.value)} className={inputStyle} placeholder="Họ và tên" /></div>
                <div><label className={labelStyle}>Chức vụ <span className="text-red-500">*</span></label><input type="text" required value={formReporterRole} onChange={(e) => setFormReporterRole(e.target.value)} className={inputStyle} placeholder="VD: Nhân viên vận hành" /></div>
              </div>
              <div><label className={labelStyle}>Chi nhánh <span className="text-red-500">*</span></label><select value={formBranchId} onChange={(e) => setFormBranchId(e.target.value)} className={inputStyle}>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
              <div><label className={labelStyle}>Hình ảnh hiện trường</label><WatermarkCamera images={formImages} onImagesChange={setFormImages} /></div>
              <div><label className={labelStyle}>Tiêu đề ngắn gọn <span className="text-red-500">*</span></label><input type="text" required value={formTitle} onChange={(e) => setFormTitle(e.target.value)} className={inputStyle} placeholder="VD: Hỏng màn hình máy game số 5" /></div>
              <div><label className={labelStyle}>Mô tả chi tiết</label><textarea value={formDesc} onChange={(e) => setFormDesc(e.target.value)} className={inputStyle} rows={3} placeholder="Mô tả cụ thể tình trạng sự cố..."></textarea></div>
              <div><label className={labelStyle}>Mức độ ưu tiên</label><select value={formSeverity} onChange={(e) => setFormSeverity(e.target.value as Severity)} className={inputStyle}><option value={Severity.LOW}>Thấp (Cần xử lý sớm)</option><option value={Severity.MEDIUM}>Trung bình (Ảnh hưởng hoạt động)</option><option value={Severity.HIGH}>KHẨN CẤP (Dừng ngay hoạt động)</option></select></div>
              <button type="submit" disabled={isSubmitting} className={`w-full bg-fkRed text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] ${isSubmitting ? 'opacity-50' : 'hover:bg-rose-700 shadow-rose-200'}`}>
                {isSubmitting ? <><i className="fas fa-circle-notch fa-spin mr-2"></i>Đang gửi...</> : 'Gửi báo cáo ngay'}
              </button>
            </form>
          </div>
        )}

        {activeTab === 'admin' && isAdminAuthenticated && (
          <AdminPanel 
            branches={branches} 
            incidents={incidents} 
            onAddBranch={handleAddBranch}
            onUpdateBranch={handleUpdateBranch}
            onDeleteBranch={handleDeleteBranch}
            onDeleteIncident={handleDeleteIncident}
          />
        )}

        {activeTab === 'export' && (
          <div className="max-w-xl mx-auto bg-white rounded-xl shadow-sm border p-10 text-center animate-fade-in">
             <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <i className="fas fa-file-excel text-green-600 text-4xl"></i>
             </div>
             <h3 className="text-xl font-bold text-gray-800">Xuất báo cáo dữ liệu</h3>
             <p className="text-gray-500 mt-2 mb-8">Tải xuống danh sách toàn bộ sự cố dưới dạng file CSV để làm báo cáo tổng hợp.</p>
             <button 
               onClick={() => { alert('Tính năng đang chuẩn bị xuất file...'); }}
               className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-green-700 shadow-lg shadow-green-100 transition-all active:scale-95"
             >
               Tải file .CSV
             </button>
          </div>
        )}
      </main>

      <AdminLoginModal 
        isOpen={showAdminLogin} 
        onClose={() => { setShowAdminLogin(false); if (window.location.hash === '#admin') window.location.hash = 'dashboard'; }} 
        onSuccess={() => {
          setIsAdminAuthenticated(true);
          setShowAdminLogin(false);
          setActiveTab('admin');
          window.location.hash = 'admin';
        }}
      />

      {showConfigModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 overflow-hidden">
            <div className="flex items-center gap-3 mb-4 text-indigo-600">
               <i className="fas fa-database text-2xl"></i>
               <h2 className="text-xl font-bold">Kết nối Supabase</h2>
            </div>
            <p className="text-gray-500 text-sm mb-6">Nhập thông tin kết nối từ Project Settings của bạn để bắt đầu lưu trữ dữ liệu.</p>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1">Project URL</label>
                <input type="text" value={configUrl} onChange={(e) => setConfigUrl(e.target.value)} className="w-full border p-3 rounded-xl mt-1 focus:ring-2 focus:ring-indigo-200 outline-none" placeholder="https://xyz.supabase.co" />
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1">Anon Key</label>
                <input type="password" value={configKey} onChange={(e) => setConfigKey(e.target.value)} className="w-full border p-3 rounded-xl mt-1 focus:ring-2 focus:ring-indigo-200 outline-none" placeholder="eyJhbG..." />
              </div>
              {connectionError && <div className="p-3 bg-red-50 text-red-600 rounded-lg text-xs font-medium flex items-center"><i className="fas fa-exclamation-triangle mr-2"></i>{connectionError}</div>}
              <div className="flex gap-3 pt-2">
                <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-100 rounded-xl transition-colors">Để sau</button>
                <button onClick={handleSaveConfig} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Lưu & Kết nối</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Branch, Incident, Severity, IncidentType, DeviceStatus } from './types';
import IncidentCard from './components/IncidentCard';
import WatermarkCamera from './components/WatermarkCamera';
import AdminPanel from './components/AdminPanel';
import AdminLoginModal from './components/AdminLoginModal';
import { playAlertSound } from './utils';
import { getSupabase, initSupabase } from './utils/supabaseClient';
import { RealtimeChannel } from '@supabase/supabase-js';

// --- SUB-COMPONENT: Branch Section ---
interface BranchSectionProps {
  branch: Branch;
  incidents: Incident[];
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
}

const BranchSection: React.FC<BranchSectionProps> = ({ branch, incidents, onUpdate }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const sortedIncidents = [...incidents].sort((a, b) => {
    const severityScore = { [Severity.HIGH]: 3, [Severity.MEDIUM]: 2, [Severity.LOW]: 1 };
    const scoreA = severityScore[a.severity] || 0;
    const scoreB = severityScore[b.severity] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    return b.timestamp - a.timestamp;
  });

  const visibleIncidents = isExpanded ? sortedIncidents : sortedIncidents.slice(0, 3);
  const hiddenCount = sortedIncidents.length - 3;
  const hasMore = sortedIncidents.length > 3;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-6 animate-fade-in">
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-fkPurple rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]"></div>
          <h2 className="text-base md:text-lg font-bold text-gray-800">{branch.name}</h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{incidents.length}</span>
        </div>
        {hasMore && (
           <button onClick={() => setIsExpanded(!isExpanded)} className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center transition-colors px-2 py-1 rounded hover:bg-indigo-50">
             {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sự cố`}
             <i className={`fas fa-chevron-${isExpanded ? 'up' : 'right'} ml-1.5`}></i>
           </button>
        )}
      </div>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-6">
        {visibleIncidents.map(incident => (
          <IncidentCard 
            key={incident.id} 
            incident={incident} 
            onUpdate={onUpdate} 
            branchName={branch.name}
          />
        ))}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'report' | 'export' | 'admin'>('dashboard');
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<string>('all');
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<'all' | 'unresolved' | 'resolved'>('unresolved');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState<'all' | IncidentType>('all');
  const [isMuted, setIsMuted] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [connectionError, setConnectionError] = useState('');

  const subscriptionRef = useRef<RealtimeChannel | null>(null);

  // Helper: Ép kiểu dữ liệu an toàn để tránh lỗi so sánh String vs Number
  const normalizeIncident = (data: any): Incident => {
    return {
      id: String(data.id),
      branchId: String(data.branch_id || data.branchId || ''),
      title: data.title || '',
      description: data.description || '',
      severity: data.severity || Severity.LOW,
      type: data.type || IncidentType.DEVICE,
      timestamp: data.timestamp ? Number(data.timestamp) : Date.now(),
      imageUrls: data.image_urls || data.imageUrls || [],
      reporterName: data.reporter_name || data.reporterName || 'N/A',
      reporterRole: data.reporter_role || data.reporterRole || 'Staff',
      isResolved: Boolean(data.is_resolved ?? data.isResolved ?? false),
      deviceStatus: data.device_status || data.deviceStatus,
      setupResponse: data.setup_response || data.setupResponse,
      resolutionNote: data.resolution_note || data.resolutionNote,
      resolutionImageUrls: data.resolution_image_urls || data.resolutionImageUrls || []
    };
  };

  const navigateTo = (tab: 'dashboard' | 'report' | 'export' | 'admin') => {
    if (tab === 'admin' && !isAdminAuthenticated) {
      setShowAdminLogin(true);
      return;
    }
    setActiveTab(tab);
    window.location.hash = tab;
  };

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '');
      if (hash === 'admin') {
        if (!isAdminAuthenticated) setShowAdminLogin(true);
        else setActiveTab('admin');
      } else if (['dashboard', 'report', 'export'].includes(hash)) {
        setActiveTab(hash as any);
      }
    };
    handleHashChange();
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isAdminAuthenticated]);

  useEffect(() => {
    const sb = getSupabase();
    if (sb) {
      setIsConfigured(true);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } else {
      setShowConfigModal(true);
    }
    return () => { if (subscriptionRef.current) subscriptionRef.current.unsubscribe(); };
  }, []);

  const setupRealtime = (sb: any) => {
    if (subscriptionRef.current) subscriptionRef.current.unsubscribe();
    subscriptionRef.current = sb.channel('all-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'incidents' }, () => { fetchIncidents(); playAlertSound(); })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, () => { fetchBranches(); })
      .subscribe();
  };

  const handleSaveConfig = () => {
    try {
      setConnectionError('');
      const sb = initSupabase(configUrl.trim(), configKey.trim());
      setIsConfigured(true);
      setShowConfigModal(false);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } catch (e) { setConnectionError('Cấu hình không hợp lệ.'); }
  };

  const fetchBranches = async () => {
    const sb = getSupabase();
    if (!sb) return;
    const { data, error } = await sb.from('branches').select('*').order('name');
    if (!error && data) {
      setBranches(data.map(b => ({ ...b, id: String(b.id) })));
    }
  };

  const fetchIncidents = async () => {
    const sb = getSupabase();
    if (!sb) return;
    setIsLoading(true);
    const { data, error } = await sb.from('incidents').select('*').order('timestamp', { ascending: false });
    if (!error && data) {
      setIncidents(data.map(normalizeIncident));
    }
    setIsLoading(false);
  };

  const handleAddBranch = async (name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').insert([{ name }]);
    fetchBranches();
  };

  const handleUpdateBranch = async (id: string, name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').update({ name }).eq('id', id);
    fetchBranches();
  };

  const handleDeleteBranch = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').delete().eq('id', id);
    fetchBranches();
  };

  const handleDeleteIncident = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('incidents').delete().eq('id', id);
    fetchIncidents();
  };

  useEffect(() => {
    const hasActiveHighSeverity = incidents.some(i => i.severity === Severity.HIGH && !i.isResolved);
    let interval: number;
    if (hasActiveHighSeverity && !isMuted) {
      playAlertSound();
      interval = window.setInterval(playAlertSound, 5000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [incidents, isMuted]);

  const [formBranchId, setFormBranchId] = useState('');
  useEffect(() => { if (branches.length > 0 && !formBranchId) setFormBranchId(branches[0].id); }, [branches]);

  const [formType, setFormType] = useState<IncidentType>(IncidentType.DEVICE);
  const [formTitle, setFormTitle] = useState('');
  const [formDesc, setFormDesc] = useState('');
  const [formSeverity, setFormSeverity] = useState<Severity>(Severity.LOW);
  const [formImages, setFormImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formReporterName, setFormReporterName] = useState('');
  const [formReporterRole, setFormReporterRole] = useState('');

  const uploadImage = async (base64Image: string): Promise<string | null> => {
    const sb = getSupabase();
    if (!sb) return null;
    try {
      const base64Str = base64Image.split(',')[1];
      const byteCharacters = atob(base64Str);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'image/jpeg' });
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.jpg`;
      const { data, error } = await sb.storage.from('incident-images').upload(fileName, blob, { contentType: 'image/jpeg' });
      if (error) return null;
      const { data: { publicUrl } } = sb.storage.from('incident-images').getPublicUrl(fileName);
      return publicUrl;
    } catch { return null; }
  };

  const handleUpdateIncident = async (id: string, updates: Partial<Incident>) => {
    const sb = getSupabase();
    if (!sb) return;
    const dbUpdates: any = { ...updates };
    if (updates.isResolved !== undefined) dbUpdates.is_resolved = updates.isResolved;
    if (updates.deviceStatus) dbUpdates.device_status = updates.deviceStatus;
    if (updates.setupResponse) dbUpdates.setup_response = updates.setupResponse;
    if (updates.resolutionNote) dbUpdates.resolution_note = updates.resolutionNote;
    if (updates.resolutionImageUrls) {
       const uploaded = await Promise.all(updates.resolutionImageUrls.map(async img => img.startsWith('data:') ? await uploadImage(img) : img));
       dbUpdates.resolution_image_urls = uploaded.filter(u => u !== null) as string[];
    }
    await sb.from('incidents').update(dbUpdates).eq('id', id);
    fetchIncidents();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sb = getSupabase();
    if (!sb) { setShowConfigModal(true); return; }
    if (!formReporterName || !formReporterRole || !formBranchId) { alert('Vui lòng điền đủ thông tin'); return; }
    setIsSubmitting(true);
    const uploadedImageUrls: string[] = [];
    for (const base64 of formImages) { const url = await uploadImage(base64); if (url) uploadedImageUrls.push(url); }
    const { error } = await sb.from('incidents').insert([{
      branch_id: formBranchId, 
      title: formTitle, 
      description: formDesc, 
      severity: formSeverity, 
      type: formType,
      timestamp: Date.now(), 
      image_urls: uploadedImageUrls, 
      reporter_name: formReporterName, 
      reporter_role: formReporterRole, 
      is_resolved: false
    }]);
    setIsSubmitting(false);
    if (!error) { fetchIncidents(); setFormTitle(''); setFormDesc(''); setFormImages([]); navigateTo('dashboard'); }
  };

  // Logic lọc dữ liệu Dashboard
  const filteredIncidents = incidents.filter(i => {
    const bMatch = selectedBranchFilter === 'all' || String(i.branchId) === String(selectedBranchFilter);
    const sMatch = selectedStatusFilter === 'all' ? true : selectedStatusFilter === 'resolved' ? i.isResolved : !i.isResolved;
    const tMatch = selectedTypeFilter === 'all' || i.type === selectedTypeFilter;
    return bMatch && sMatch && tMatch;
  });

  // Chỉ hiển thị những chi nhánh có sự cố khớp với bộ lọc
  const branchesToShow = branches.filter(b => {
    const hasIncidents = filteredIncidents.some(i => String(i.branchId) === String(b.id));
    const isSelected = selectedBranchFilter === 'all' || String(b.id) === String(selectedBranchFilter);
    return isSelected && hasIncidents;
  });

  const inputStyle = "w-full rounded-lg border border-indigo-500 bg-white text-black text-base p-3 focus:border-indigo-700 focus:ring-2 focus:ring-indigo-200 outline-none transition-all placeholder-gray-400 font-medium appearance-none";
  const labelStyle = "block text-sm font-bold text-gray-700 mb-2";

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      <header className="bg-gradient-to-r from-fkRed to-fkPurple text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-screen-xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center space-x-3 cursor-pointer group" onClick={() => navigateTo('dashboard')}>
            <div className="bg-white/20 p-2 rounded-full group-hover:bg-white/30 transition-colors"><i className="fas fa-child text-xl md:text-2xl"></i></div>
            <div><h1 className="text-lg md:text-xl font-bold tracking-tight">FunnyKids</h1><span className="text-xs font-light opacity-80">Incident Manager</span></div>
          </div>
          <div className="flex items-center gap-1.5 md:gap-2">
            <button 
              onClick={() => navigateTo('admin')} 
              className={`p-2 rounded-lg border transition-all flex items-center gap-2 ${activeTab === 'admin' ? 'bg-white text-indigo-600 border-white' : 'bg-white/10 text-white border-white/20 hover:bg-white/20'}`}
              title="Quản trị hệ thống"
            >
              <i className="fas fa-user-shield"></i>
              <span className="text-[10px] font-bold hidden sm:inline uppercase tracking-wider">Admin</span>
            </button>
            <button onClick={() => setShowConfigModal(true)} className="p-2 rounded-lg bg-white/10 hover:bg-white/20 border border-white/20 transition-all"><i className="fas fa-cog"></i></button>
            <button onClick={() => setIsMuted(!isMuted)} className={`flex items-center gap-2 px-3 py-2 rounded-lg border ${isMuted ? 'bg-red-500/20 text-red-100 border-red-400/50' : 'bg-white/10 text-white border-white/20'}`}>
              <i className={`fas ${isMuted ? 'fa-volume-mute' : 'fa-volume-up'}`}></i><span className="text-xs font-bold hidden md:inline">{isMuted ? 'Muted' : 'Sound'}</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="bg-white shadow-sm border-b sticky top-[60px] z-40">
        <div className="max-w-screen-xl mx-auto flex">
          <button onClick={() => navigateTo('dashboard')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'dashboard' ? 'border-fkPurple text-fkPurple bg-indigo-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-th-large"></i></div>Theo dõi
          </button>
          <button onClick={() => navigateTo('report')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'report' ? 'border-fkRed text-fkRed bg-red-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-plus-circle"></i></div>Báo cáo
          </button>
          <button onClick={() => navigateTo('export')} className={`flex-1 py-3 text-center text-xs md:text-sm font-bold border-b-2 transition-all ${activeTab === 'export' ? 'border-green-600 text-green-600 bg-green-50/30' : 'border-transparent text-gray-400'}`}>
            <div className="mb-1"><i className="fas fa-file-export"></i></div>Xuất file
          </button>
        </div>
      </nav>

      <main className="flex-grow max-w-screen-xl w-full mx-auto px-4 py-6">
        {activeTab === 'dashboard' && (
          <div className="space-y-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-col md:flex-row gap-4 items-end">
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Trạng thái</label>
               <select value={selectedStatusFilter} onChange={(e) => setSelectedStatusFilter(e.target.value as any)} className={inputStyle}><option value="unresolved">Chưa xử lý</option><option value="resolved">Đã xử lý</option><option value="all">Tất cả</option></select></div>
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Loại sự cố</label>
               <select value={selectedTypeFilter} onChange={(e) => setSelectedTypeFilter(e.target.value as any)} className={inputStyle}><option value="all">Tất cả loại</option><option value={IncidentType.DEVICE}>Thiết bị</option><option value={IncidentType.GAME}>Máy game</option><option value={IncidentType.ACCIDENT}>Tai nạn</option></select></div>
               <div className="flex-1 w-full"><label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Chi nhánh</label>
               <select value={selectedBranchFilter} onChange={(e) => setSelectedBranchFilter(e.target.value)} className={inputStyle}><option value="all">Tất cả chi nhánh</option>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
               <button onClick={fetchIncidents} className="p-3 bg-indigo-50 text-indigo-600 rounded-lg border border-indigo-200 hover:bg-indigo-100 transition-colors" title="Làm mới"><i className={`fas fa-sync-alt ${isLoading ? 'fa-spin' : ''}`}></i></button>
            </div>

            {isLoading ? (
              <div className="text-center py-20 animate-pulse">
                <i className="fas fa-circle-notch fa-spin text-4xl text-indigo-400 mb-2"></i>
                <p className="text-gray-400 font-medium">Đang tải dữ liệu...</p>
              </div>
            ) : branchesToShow.length > 0 ? (
              branchesToShow.map(branch => {
                const bIncidents = filteredIncidents.filter(i => String(i.branchId) === String(branch.id));
                return <BranchSection key={branch.id} branch={branch} incidents={bIncidents} onUpdate={handleUpdateIncident} />;
              })
            ) : (
              <div className="text-center py-20 bg-white rounded-2xl border-2 border-dashed border-gray-200 animate-fade-in">
                <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-search text-gray-300 text-4xl"></i>
                </div>
                <h3 className="text-lg font-bold text-gray-700">Không tìm thấy sự cố nào</h3>
                <p className="text-gray-500 max-w-xs mx-auto mt-2 text-sm">Vui lòng kiểm tra lại bộ lọc hoặc đảm bảo dữ liệu trong database đã được nhập đúng định dạng.</p>
                <button onClick={() => { setSelectedStatusFilter('all'); setSelectedBranchFilter('all'); setSelectedTypeFilter('all'); }} className="mt-6 text-indigo-600 font-bold hover:underline text-sm">Xóa tất cả bộ lọc</button>
              </div>
            )}
          </div>
        )}

        {activeTab === 'report' && (
          <div className="max-w-3xl mx-auto bg-white rounded-xl shadow-lg p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-6 border-b pb-4 flex items-center">
              <i className="fas fa-edit mr-3 text-fkRed"></i> Báo cáo sự cố mới
            </h2>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(t => (
                  <div key={t} onClick={() => setFormType(t)} className={`cursor-pointer border-2 p-4 rounded-lg flex flex-col items-center transition-all ${formType === t ? 'border-fkPurple bg-indigo-50 text-indigo-700' : 'border-gray-100 bg-gray-50/30'}`}>
                    <i className={`fas ${t === IncidentType.DEVICE ? 'fa-tools' : t === IncidentType.GAME ? 'fa-gamepad' : 'fa-user-injured'} text-2xl mb-2`}></i>
                    <span className="font-bold text-sm">{t === IncidentType.DEVICE ? 'Thiết bị' : t === IncidentType.GAME ? 'Máy game' : 'Tai nạn'}</span>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className={labelStyle}>Người báo <span className="text-red-500">*</span></label><input type="text" required value={formReporterName} onChange={(e) => setFormReporterName(e.target.value)} className={inputStyle} placeholder="Họ và tên" /></div>
                <div><label className={labelStyle}>Chức vụ <span className="text-red-500">*</span></label><input type="text" required value={formReporterRole} onChange={(e) => setFormReporterRole(e.target.value)} className={inputStyle} placeholder="VD: Nhân viên vận hành" /></div>
              </div>
              <div><label className={labelStyle}>Chi nhánh <span className="text-red-500">*</span></label><select value={formBranchId} onChange={(e) => setFormBranchId(e.target.value)} className={inputStyle}>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
              <div><label className={labelStyle}>Hình ảnh hiện trường</label><WatermarkCamera images={formImages} onImagesChange={setFormImages} /></div>
              <div><label className={labelStyle}>Tiêu đề ngắn gọn <span className="text-red-500">*</span></label><input type="text" required value={formTitle} onChange={(e) => setFormTitle(e.target.value)} className={inputStyle} placeholder="VD: Hỏng màn hình máy game số 5" /></div>
              <div><label className={labelStyle}>Mô tả chi tiết</label><textarea value={formDesc} onChange={(e) => setFormDesc(e.target.value)} className={inputStyle} rows={3} placeholder="Mô tả cụ thể tình trạng sự cố..."></textarea></div>
              <div><label className={labelStyle}>Mức độ ưu tiên</label><select value={formSeverity} onChange={(e) => setFormSeverity(e.target.value as Severity)} className={inputStyle}><option value={Severity.LOW}>Thấp (Cần xử lý sớm)</option><option value={Severity.MEDIUM}>Trung bình (Ảnh hưởng hoạt động)</option><option value={Severity.HIGH}>KHẨN CẤP (Dừng ngay hoạt động)</option></select></div>
              <button type="submit" disabled={isSubmitting} className={`w-full bg-fkRed text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] ${isSubmitting ? 'opacity-50' : 'hover:bg-rose-700 shadow-rose-200'}`}>
                {isSubmitting ? <><i className="fas fa-circle-notch fa-spin mr-2"></i>Đang gửi...</> : 'Gửi báo cáo ngay'}
              </button>
            </form>
          </div>
        )}

        {activeTab === 'admin' && isAdminAuthenticated && (
          <AdminPanel 
            branches={branches} 
            incidents={incidents} 
            onAddBranch={handleAddBranch}
            onUpdateBranch={handleUpdateBranch}
            onDeleteBranch={handleDeleteBranch}
            onDeleteIncident={handleDeleteIncident}
          />
        )}

        {activeTab === 'export' && (
          <div className="max-w-xl mx-auto bg-white rounded-xl shadow-sm border p-10 text-center animate-fade-in">
             <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <i className="fas fa-file-excel text-green-600 text-4xl"></i>
             </div>
             <h3 className="text-xl font-bold text-gray-800">Xuất báo cáo dữ liệu</h3>
             <p className="text-gray-500 mt-2 mb-8">Tải xuống danh sách toàn bộ sự cố dưới dạng file CSV để làm báo cáo tổng hợp.</p>
             <button 
               onClick={() => { alert('Tính năng đang chuẩn bị xuất file...'); }}
               className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-green-700 shadow-lg shadow-green-100 transition-all active:scale-95"
             >
               Tải file .CSV
             </button>
          </div>
        )}
      </main>

      <AdminLoginModal 
        isOpen={showAdminLogin} 
        onClose={() => { setShowAdminLogin(false); if (window.location.hash === '#admin') window.location.hash = 'dashboard'; }} 
        onSuccess={() => {
          setIsAdminAuthenticated(true);
          setShowAdminLogin(false);
          setActiveTab('admin');
          window.location.hash = 'admin';
        }}
      />

      {showConfigModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 overflow-hidden">
            <div className="flex items-center gap-3 mb-4 text-indigo-600">
               <i className="fas fa-database text-2xl"></i>
               <h2 className="text-xl font-bold">Kết nối Supabase</h2>
            </div>
            <p className="text-gray-500 text-sm mb-6">Nhập thông tin kết nối từ Project Settings của bạn để bắt đầu lưu trữ dữ liệu.</p>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1">Project URL</label>
                <input type="text" value={configUrl} onChange={(e) => setConfigUrl(e.target.value)} className="w-full border p-3 rounded-xl mt-1 focus:ring-2 focus:ring-indigo-200 outline-none" placeholder="https://xyz.supabase.co" />
              </div>
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase ml-1">Anon Key</label>
                <input type="password" value={configKey} onChange={(e) => setConfigKey(e.target.value)} className="w-full border p-3 rounded-xl mt-1 focus:ring-2 focus:ring-indigo-200 outline-none" placeholder="eyJhbG..." />
              </div>
              {connectionError && <div className="p-3 bg-red-50 text-red-600 rounded-lg text-xs font-medium flex items-center"><i className="fas fa-exclamation-triangle mr-2"></i>{connectionError}</div>}
              <div className="flex gap-3 pt-2">
                <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 text-gray-500 font-bold hover:bg-gray-100 rounded-xl transition-colors">Để sau</button>
                <button onClick={handleSaveConfig} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Lưu & Kết nối</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Branch, Incident, Severity, IncidentType, DeviceStatus } from './types';
import IncidentCard from './components/IncidentCard';
import WatermarkCamera from './components/WatermarkCamera';
import AdminPanel from './components/AdminPanel';
import AdminLoginModal from './components/AdminLoginModal';
import { playAlertSound } from './utils';
import { getSupabase, initSupabase } from './utils/supabaseClient';
import { RealtimeChannel } from '@supabase/supabase-js';

// --- SUB-COMPONENT: Branch Section ---
interface BranchSectionProps {
  branch: Branch;
  incidents: Incident[];
  onUpdate: (id: string, updates: Partial<Incident>) => Promise<void>;
}

const BranchSection: React.FC<BranchSectionProps> = ({ branch, incidents, onUpdate }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const sortedIncidents = [...incidents].sort((a, b) => {
    const severityScore = { [Severity.HIGH]: 3, [Severity.MEDIUM]: 2, [Severity.LOW]: 1 };
    const scoreA = severityScore[a.severity] || 0;
    const scoreB = severityScore[b.severity] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    return b.timestamp - a.timestamp;
  });

  const visibleIncidents = isExpanded ? sortedIncidents : sortedIncidents.slice(0, 3);
  const hiddenCount = sortedIncidents.length - 3;
  const hasMore = sortedIncidents.length > 3;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden mb-6 animate-fade-in">
      <div className="px-4 py-3 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-1 h-6 bg-fkPurple rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]"></div>
          <h2 className="text-base md:text-lg font-bold text-gray-800">{branch.name}</h2>
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded-full">{incidents.length}</span>
        </div>
        {hasMore && (
           <button onClick={() => setIsExpanded(!isExpanded)} className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center transition-colors px-2 py-1 rounded hover:bg-indigo-50">
             {isExpanded ? 'Thu gọn' : `Xem thêm ${hiddenCount} sự cố`}
             <i className={`fas fa-chevron-${isExpanded ? 'up' : 'right'} ml-1.5`}></i>
           </button>
        )}
      </div>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 md:gap-6">
        {visibleIncidents.map(incident => (
          <IncidentCard 
            key={incident.id} 
            incident={incident} 
            onUpdate={onUpdate} 
            branchName={branch.name}
          />
        ))}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'report' | 'export' | 'admin'>('dashboard');
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Dashboard Filters
  const [selectedBranchFilter, setSelectedBranchFilter] = useState<string>('all');
  const [selectedStatusFilter, setSelectedStatusFilter] = useState<'all' | 'unresolved' | 'resolved'>('unresolved');
  const [selectedTypeFilter, setSelectedTypeFilter] = useState<'all' | IncidentType>('all');

  // Export Filters
  const [exportBranch, setExportBranch] = useState('all');
  const [exportType, setExportType] = useState('all');
  const [exportStartDate, setExportStartDate] = useState('');
  const [exportEndDate, setExportEndDate] = useState('');

  const [isMuted, setIsMuted] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);
  const [configUrl, setConfigUrl] = useState('');
  const [configKey, setConfigKey] = useState('');
  const [connectionError, setConnectionError] = useState('');

  const subscriptionRef = useRef<RealtimeChannel | null>(null);

  const normalizeIncident = (data: any): Incident => {
    return {
      id: String(data.id),
      branchId: String(data.branch_id || data.branchId || ''),
      title: data.title || '',
      description: data.description || '',
      severity: data.severity || Severity.LOW,
      type: data.type || IncidentType.DEVICE,
      timestamp: data.timestamp ? Number(data.timestamp) : Date.now(),
      imageUrls: data.image_urls || data.imageUrls || [],
      reporterName: data.reporter_name || data.reporterName || 'N/A',
      reporterRole: data.reporter_role || data.reporterRole || 'Staff',
      isResolved: Boolean(data.is_resolved ?? data.isResolved ?? false),
      deviceStatus: data.device_status || data.deviceStatus,
      setupResponse: data.setup_response || data.setupResponse,
      resolutionNote: data.resolution_note || data.resolutionNote,
      resolutionImageUrls: data.resolution_image_urls || data.resolutionImageUrls || []
    };
  };

  const navigateTo = (tab: 'dashboard' | 'report' | 'export' | 'admin') => {
    if (tab === 'admin' && !isAdminAuthenticated) {
      setShowAdminLogin(true);
      return;
    }
    setActiveTab(tab);
    window.location.hash = tab;
  };

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '');
      if (hash === 'admin') {
        if (!isAdminAuthenticated) setShowAdminLogin(true);
        else setActiveTab('admin');
      } else if (['dashboard', 'report', 'export'].includes(hash)) {
        setActiveTab(hash as any);
      }
    };
    handleHashChange();
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [isAdminAuthenticated]);

  useEffect(() => {
    const sb = getSupabase();
    if (sb) {
      setIsConfigured(true);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } else {
      setShowConfigModal(true);
    }
    return () => { if (subscriptionRef.current) subscriptionRef.current.unsubscribe(); };
  }, []);

  const setupRealtime = (sb: any) => {
    if (subscriptionRef.current) subscriptionRef.current.unsubscribe();
    subscriptionRef.current = sb.channel('all-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'incidents' }, () => { fetchIncidents(); playAlertSound(); })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'branches' }, () => { fetchBranches(); })
      .subscribe();
  };

  const handleSaveConfig = () => {
    try {
      setConnectionError('');
      const sb = initSupabase(configUrl.trim(), configKey.trim());
      setIsConfigured(true);
      setShowConfigModal(false);
      fetchBranches();
      fetchIncidents();
      setupRealtime(sb);
    } catch (e) { setConnectionError('Cấu hình không hợp lệ.'); }
  };

  const fetchBranches = async () => {
    const sb = getSupabase();
    if (!sb) return;
    const { data, error } = await sb.from('branches').select('*').order('name');
    if (!error && data) {
      setBranches(data.map(b => ({ ...b, id: String(b.id) })));
    }
  };

  const fetchIncidents = async () => {
    const sb = getSupabase();
    if (!sb) return;
    setIsLoading(true);
    const { data, error } = await sb.from('incidents').select('*').order('timestamp', { ascending: false });
    if (!error && data) {
      setIncidents(data.map(normalizeIncident));
    }
    setIsLoading(false);
  };

  // --- LOGIC XUẤT FILE ---
  const filteredExportData = useMemo(() => {
    return incidents.filter(i => {
      const bMatch = exportBranch === 'all' || String(i.branchId) === String(exportBranch);
      const tMatch = exportType === 'all' || i.type === exportType;

      let dateMatch = true;
      if (exportStartDate) {
        const start = new Date(exportStartDate).getTime();
        dateMatch = dateMatch && i.timestamp >= start;
      }
      if (exportEndDate) {
        const end = new Date(exportEndDate).getTime() + (24 * 60 * 60 * 1000); // Tới cuối ngày
        dateMatch = dateMatch && i.timestamp <= end;
      }

      return bMatch && tMatch && dateMatch;
    });
  }, [incidents, exportBranch, exportType, exportStartDate, exportEndDate]);

  const exportStats = useMemo(() => ({
    total: filteredExportData.length,
    resolved: filteredExportData.filter(i => i.isResolved).length,
    device: filteredExportData.filter(i => i.type === IncidentType.DEVICE).length,
    game: filteredExportData.filter(i => i.type === IncidentType.GAME).length,
    accident: filteredExportData.filter(i => i.type === IncidentType.ACCIDENT).length,
  }), [filteredExportData]);

  const downloadCSV = () => {
    if (filteredExportData.length === 0) {
      alert("Không có dữ liệu để xuất!");
      return;
    }

    const headers = ["ID", "Chi nhánh", "Tiêu đề", "Loại", "Mức độ", "Thời gian", "Người báo", "Trạng thái", "Nội dung xử lý"];
    const csvContent = [
      headers.join(","),
      ...filteredExportData.map(i => {
        const branchName = branches.find(b => String(b.id) === String(i.branchId))?.name || "N/A";
        const date = new Date(i.timestamp).toLocaleString('vi-VN');
        const status = i.isResolved ? "Đã xong" : "Chưa xong";
        return [
          i.id,
          `"${branchName}"`,
          `"${i.title.replace(/"/g, '""')}"`,
          i.type,
          i.severity,
          `"${date}"`,
          `"${i.reporterName}"`,
          status,
          `"${(i.resolutionNote || "").replace(/"/g, '""')}"`
        ].join(",");
      })
    ].join("\n");

    const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Bao_cao_su_co_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Admin Actions
  const handleAddBranch = async (name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').insert([{ name }]);
    fetchBranches();
  };

  const handleUpdateBranch = async (id: string, name: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').update({ name }).eq('id', id);
    fetchBranches();
  };

  const handleDeleteBranch = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('branches').delete().eq('id', id);
    fetchBranches();
  };

  const handleDeleteIncident = async (id: string) => {
    const sb = getSupabase();
    if (!sb) return;
    await sb.from('incidents').delete().eq('id', id);
    fetchIncidents();
  };

  const handleUpdateIncident = async (id: string, updates: Partial<Incident>) => {
    const sb = getSupabase();
    if (!sb) return;
    const dbUpdates: any = { ...updates };
    if (updates.isResolved !== undefined) dbUpdates.is_resolved = updates.isResolved;
    if (updates.deviceStatus) dbUpdates.device_status = updates.deviceStatus;
    if (updates.setupResponse) dbUpdates.setup_response = updates.setupResponse;
    if (updates.resolutionNote) dbUpdates.resolution_note = updates.resolutionNote;
    await sb.from('incidents').update(dbUpdates).eq('id', id);
    fetchIncidents();
  };

  // Audio Logic
  useEffect(() => {
    const hasActiveHighSeverity = incidents.some(i => i.severity === Severity.HIGH && !i.isResolved);
    let interval: number;
    if (hasActiveHighSeverity && !isMuted) {
      playAlertSound();
      interval = window.setInterval(playAlertSound, 5000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [incidents, isMuted]);

  // Form State Report
  const [formBranchId, setFormBranchId] = useState('');
  useEffect(() => { if (branches.length > 0 && !formBranchId) setFormBranchId(branches[0].id); }, [branches]);
  const [formType, setFormType] = useState<IncidentType>(IncidentType.DEVICE);
  const [formTitle, setFormTitle] = useState('');
  const [formDesc, setFormDesc] = useState('');
  const [formSeverity, setFormSeverity] = useState<Severity>(Severity.LOW);
  const [formImages, setFormImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formReporterName, setFormReporterName] = useState('');
  const [formReporterRole, setFormReporterRole] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sb = getSupabase();
    if (!sb) { setShowConfigModal(true); return; }
    setIsSubmitting(true);
    const { error } = await sb.from('incidents').insert([{
      branch_id: formBranchId, 
      title: formTitle, 
      description: formDesc, 
      severity: formSeverity, 
      type: formType,
      timestamp: Date.now(), 
      image_urls: formImages, 
      reporter_name: formReporterName, 
      reporter_role: formReporterRole, 
      is_resolved: false
    }]);
    setIsSubmitting(false);
    if (!error) { fetchIncidents(); setFormTitle(''); setFormDesc(''); setFormImages([]); navigateTo('dashboard'); }
  };

  const filteredIncidents = incidents.filter(i => {
    const bMatch = selectedBranchFilter === 'all' || String(i.branchId) === String(selectedBranchFilter);
    const sMatch = selectedStatusFilter === 'all' ? true : selectedStatusFilter === 'resolved' ? i.isResolved : !i.isResolved;
    const tMatch = selectedTypeFilter === 'all' || i.type === selectedTypeFilter;
    return bMatch && sMatch && tMatch;
  });

