        {activeTab === 'report' && (
          <div className="max-w-3xl mx-auto bg-white rounded-xl shadow-lg p-6 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-6 border-b pb-4 flex items-center"><i className="fas fa-edit mr-3 text-fkRed"></i> Báo cáo sự cố mới</h2>
            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {[IncidentType.DEVICE, IncidentType.GAME, IncidentType.ACCIDENT].map(t => (
