                    <i className={`fas ${t === IncidentType.DEVICE ? 'fa-tools' : t === IncidentType.GAME ? 'fa-gamepad' : 'fa-user-injured'} text-2xl mb-2`}></i>
                    <span className="font-bold text-sm">{t === IncidentType.DEVICE ? 'Thiết bị' : t === IncidentType.GAME ? 'Máy game' : 'Tai nạn'}</span>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className={labelStyle}>Người báo *</label><input type="text" required value={formReporterName} onChange={(e) => setFormReporterName(e.target.value)} className={inputStyle} /></div>
                <div><label className={labelStyle}>Chức vụ *</label><input type="text" required value={formReporterRole} onChange={(e) => setFormReporterRole(e.target.value)} className={inputStyle} /></div>
              </div>
              <div><label className={labelStyle}>Chi nhánh *</label><select value={formBranchId} onChange={(e) => setFormBranchId(e.target.value)} className={inputStyle}>{branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}</select></div>
              <div><label className={labelStyle}>Hình ảnh hiện trường</label><WatermarkCamera images={formImages} onImagesChange={setFormImages} /></div>
              <div><label className={labelStyle}>Tiêu đề *</label><input type="text" required value={formTitle} onChange={(e) => setFormTitle(e.target.value)} className={inputStyle} /></div>
              <div><label className={labelStyle}>Mô tả</label><textarea value={formDesc} onChange={(e) => setFormDesc(e.target.value)} className={inputStyle} rows={3}></textarea></div>
              <div><label className={labelStyle}>Mức độ</label><select value={formSeverity} onChange={(e) => setFormSeverity(e.target.value as Severity)} className={inputStyle}><option value={Severity.LOW}>Thấp</option><option value={Severity.MEDIUM}>Trung bình</option><option value={Severity.HIGH}>KHẨN CẤP</option></select></div>
              <button type="submit" disabled={isSubmitting} className="w-full bg-fkRed text-white font-bold py-4 rounded-xl shadow-lg hover:bg-rose-700">{isSubmitting ? 'Đang gửi...' : 'Gửi báo cáo ngay'}</button>
            </form>
          </div>
        )}

        {activeTab === 'export' && (
          <div className="max-w-xl mx-auto space-y-8 animate-fade-in-up">
