              <div>
                <label className={labelStyle}>Thời gian</label>
                <div className="relative group">
                  <div className="w-full rounded-lg border border-indigo-200 bg-white p-4 text-center text-xl font-medium shadow-sm flex items-center justify-center gap-2 group-active:scale-[0.99] transition-transform cursor-pointer">
                     {(() => {
                        const [y, m] = exportMonthYear.split('-');
                        return `tháng ${m} năm ${y}`;
                     })()}
