                    {branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                  </select>
                  <div className="pointer-events-none absolute inset-y-0 right-4 flex items-center text-gray-400">
                    <i className="fas fa-chevron-down text-sm"></i>
                  </div>
                </div>
              </div>
            </div>

            {/* PHẦN TỔNG QUAN THEO MẪU */}
            <div className="bg-indigo-50/50 rounded-2xl p-6 md:p-8 space-y-6 border border-indigo-100/50">
              <h3 className="text-sm font-bold text-indigo-900 uppercase tracking-widest text-center opacity-70">TỔNG QUAN</h3>

              <div className="grid grid-cols-3 gap-3 md:gap-4">
                <div className="bg-white p-3 md:p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                  <div className="text-2xl md:text-3xl font-black text-slate-800 mb-1">{exportStats.total}</div>
                  <div className="text-[10px] md:text-xs font-bold text-gray-400">Tổng số</div>
                </div>
                <div className="bg-white p-3 md:p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                  <div className="text-2xl md:text-3xl font-black text-green-500 mb-1">{exportStats.resolved}</div>
                  <div className="text-[10px] md:text-xs font-bold text-gray-400">Đã xử lý</div>
                </div>
                <div className="bg-white p-3 md:p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                  <div className="text-2xl md:text-3xl font-black text-blue-500 mb-1">{exportStats.device}</div>
                  <div className="text-[10px] md:text-xs font-bold text-gray-400">Thiết bị</div>
                </div>
                <div className="bg-white p-3 md:p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                  <div className="text-2xl md:text-3xl font-black text-purple-500 mb-1">{exportStats.game}</div>
                  <div className="text-[10px] md:text-xs font-bold text-gray-400">Máy game</div>
                </div>
                <div className="bg-white p-3 md:p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                  <div className="text-2xl md:text-3xl font-black text-rose-500 mb-1">{exportStats.accident}</div>
                  <div className="text-[10px] md:text-xs font-bold text-gray-400">Tai nạn</div>
                </div>
                <button 
                  onClick={downloadCSV}
                  className="bg-green-500 p-3 md:p-5 rounded-xl shadow-md border border-green-600 flex flex-col items-center justify-center text-white hover:bg-green-600 active:scale-95 transition-all"
                >
                  <i className="fas fa-file-csv text-xl md:text-2xl mb-1"></i>
                  <div className="text-[10px] md:text-xs font-bold">Tải File</div>
                </button>
              </div>
            </div>

            <p className="text-center text-gray-400 text-xs italic">Dữ liệu được cập nhật thời gian thực từ hệ thống.</p>
          </div>
        )}

        {activeTab === 'admin' && isAdminAuthenticated && (
          <AdminPanel 
            branches={branches} 
            incidents={incidents} 
            onAddBranch={handleAddBranch}
            onUpdateBranch={handleUpdateBranch}
            onDeleteBranch={handleDeleteBranch}
            onDeleteIncident={handleDeleteIncident}
          />
        )}
      </main>

      <AdminLoginModal isOpen={showAdminLogin} onClose={() => { setShowAdminLogin(false); if(window.location.hash==='#admin') window.location.hash='dashboard'; }} onSuccess={() => { setIsAdminAuthenticated(true); setShowAdminLogin(false); setActiveTab('admin'); window.location.hash='admin'; }} />
      {showConfigModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 overflow-hidden">
            <h2 className="text-xl font-bold mb-4">Kết nối Supabase</h2>
            <div className="space-y-4">
              <input type="text" value={configUrl} onChange={(e) => setConfigUrl(e.target.value)} className="w-full border p-3 rounded-xl" placeholder="Project URL" />
              <input type="password" value={configKey} onChange={(e) => setConfigKey(e.target.value)} className="w-full border p-3 rounded-xl" placeholder="Anon Key" />
              {connectionError && <div className="text-red-500 text-sm">{connectionError}</div>}
              <div className="flex gap-3"><button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 bg-gray-100 font-bold rounded-xl">Đóng</button><button onClick={handleSaveConfig} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold">Kết nối</button></div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
